export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
  });

  // Load from storage on mount
  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed }));
      } catch (e) {
        console.error("Failed to load layout", e);
      }
    }
  }, []);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Layout saved to browser!");
  };

  const addItem = (type: FurnitureType) => {
    const data = FURNITURE_DATA[type];
    const currentCount = state.placedItems.filter(i => i.type === type).length;

    if (currentCount >= data.maxQuantity) {
      alert(`Maximum of ${data.maxQuantity} ${data.name}s reached.`);
      return;
    }

    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };

    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => 
        i.instanceId === state.selectedId 
          ? { ...i, rotation: i.rotation + Math.PI / 2 } 
          : i
      ),
    }));
  };

  const resetRoom = () => {
    if (confirm("Clear all furniture?")) {
      setState(prev => ({ ...prev, placedItems: [], selectedId: null }));
    }
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    // Snap to grid
    const snappedPos: [number, number, number] = [
      Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE,
      0,
      Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE,
    ];

    // Bounds check
    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;
    const dims = FURNITURE_DATA[item.type].dimensions;
    const halfW = dims.width / 2;
    const halfD = dims.depth / 2;

    const limitX = state.room.width / 2;
    const limitZ = state.room.depth / 2;

    snappedPos[0] = Math.max(-limitX + halfW, Math.min(limitX - halfW, snappedPos[0]));
    snappedPos[2] = Math.max(-limitZ + halfD, Math.min(limitZ - halfD, snappedPos[2]));

    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => 
        i.instanceId === id ? { ...i, position: snappedPos } : i
      ),
    }));
  }, [state.placedItems, state.room]);

  return (
    <div className="flex h-screen bg-gray-100 flex-col md:flex-row overflow-hidden">
      {/* Sidebar - Toolbar */}
      <aside className="w-full md:w-80 bg-white shadow-xl flex flex-col z-20 overflow-y-auto">
        <div className="p-6 border-b bg-blue-600 text-white">
          <h1 className="text-xl font-bold">Hostel Planner 3D</h1>
          <p className="text-sm opacity-80">Design your perfect space</p>
        </div>

        <div className="p-6 space-y-6">
          <section>
            <h2 className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Add Furniture</h2>
            <div className="grid grid-cols-1 gap-3">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                const count = state.placedItems.filter(i => i.type === type).length;
                const isLimit = count >= item.maxQuantity;

                return (
                  <button
                    key={type}
                    disabled={isLimit}
                    onClick={() => addItem(type)}
                    className={`flex items-center justify-between p-4 rounded-xl border-2 transition-all group ${
                      isLimit 
                      ? 'border-gray-100 bg-gray-50 text-gray-400 cursor-not-allowed' 
                      : 'border-blue-50 hover:border-blue-500 hover:bg-blue-50 text-gray-700'
                    }`}
                  >
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-medium">{item.name}</div>
                        <div className="text-xs opacity-70">
                          {item.dimensions.width}' x {item.dimensions.depth}'
                        </div>
                      </div>
                    </div>
                    <div className="flex flex-col items-end">
                       <Plus size={18} className={isLimit ? 'hidden' : 'text-blue-500'} />
                       <span className="text-[10px] mt-1">{count}/{item.maxQuantity}</span>
                    </div>
                  </button>
                );
              })}
            </div>
          </section>

          <section>
             <h2 className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Controls</h2>
             <div className="grid grid-cols-2 gap-2">
                <button 
                  onClick={saveLayout}
                  className="flex items-center justify-center space-x-2 py-3 px-4 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors"
                >
                  <Save size={18} /> <span>Save</span>
                </button>
                <button 
                  onClick={resetRoom}
                  className="flex items-center justify-center space-x-2 py-3 px-4 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors"
                >
                  <RotateCcw size={18} /> <span>Reset</span>
                </button>
             </div>
          </section>

          {state.selectedId && (
            <section className="animate-in fade-in slide-in-from-bottom-2">
              <h2 className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Selection Actions</h2>
              <div className="bg-blue-50 p-4 rounded-xl border border-blue-200">
                <div className="flex justify-between items-center mb-4">
                  <span className="text-sm font-semibold text-blue-900">
                    {FURNITURE_DATA[state.placedItems.find(i => i.instanceId === state.selectedId)!.type].name}
                  </span>
                </div>
                <div className="grid grid-cols-2 gap-2">
                  <button 
                    onClick={rotateItem}
                    className="flex items-center justify-center space-x-2 py-2 bg-white border border-blue-300 rounded-lg hover:bg-blue-100 transition-colors text-blue-800"
                  >
                    <RotateCw size={18} /> <span>Rotate 90°</span>
                  </button>
                  <button 
                    onClick={removeItem}
                    className="flex items-center justify-center space-x-2 py-2 bg-white border border-red-300 rounded-lg hover:bg-red-100 transition-colors text-red-600"
                  >
                    <Trash2 size={18} /> <span>Remove</span>
                  </button>
                </div>
              </div>
            </section>
          )}
        </div>
      </aside>

      {/* Main Canvas Area */}
      <main className="flex-1 relative bg-gray-200">
        <div className="absolute top-4 right-4 z-10 flex flex-col space-y-2">
          <button 
            onClick={() => setState(p => ({ ...p, showGrid: !p.showGrid }))}
            className={`p-3 rounded-full shadow-lg transition-colors ${state.showGrid ? 'bg-blue-600 text-white' : 'bg-white text-gray-700'}`}
            title="Toggle Grid"
          >
            <Grid3X3 size={20} />
          </button>
          <button 
             onClick={() => setState(p => ({ ...p, is2D: !p.is2D }))}
             className={`p-3 rounded-full shadow-lg transition-colors ${state.is2D ? 'bg-blue-600 text-white' : 'bg-white text-gray-700'}`}
             title="Switch View"
          >
            {state.is2D ? <Maximize size={20} /> : <Layers size={20} />}
          </button>
        </div>

        {/* View overlay info */}
        <div className="absolute bottom-4 left-4 z-10 pointer-events-none">
          <div className="bg-black/50 backdrop-blur-sm text-white px-4 py-2 rounded-lg text-sm">
             <p className="font-medium">Room Size: {state.room.width}ft x {state.room.depth}ft</p>
             <p className="text-xs opacity-80">Click furniture to select. Drag to move.</p>
          </div>
        </div>

        <Canvas shadows dpr={[1, 2]}>
          <PerspectiveCamera 
            makeDefault 
            position={state.is2D ? [0, 20, 0] : [15, 15, 15]} 
            fov={state.is2D ? 40 : 50} 
          />

          <OrbitControls 
            enableRotate={!state.is2D} 
            maxPolarAngle={Math.PI / 2.1} 
            makeDefault 
          />

          <ambientLight intensity={0.7} />
          <pointLight position={[10, 10, 10]} intensity={1} castShadow />
          <spotLight position={[-10, 10, 10]} angle={0.15} penumbra={1} intensity={0.5} castShadow />
          <Environment preset="city" />

          {/* Room Environment */}
          <Room 
            config={state.room} 
            showGrid={state.showGrid} 
            onDeselect={() => setState(p => ({ ...p, selectedId: null }))}
          />

          {/* Furniture Instances */}
          {state.placedItems.map((item) => (
            <DraggableFurniture
              key={item.instanceId}
              item={item}
              selected={state.selectedId === item.instanceId}
              onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))}
              onDrag={(pos) => handleDrag(item.instanceId, pos)}
            />
          ))}

          <ContactShadows resolution={1024} scale={20} blur={2} opacity={0.3} far={10} color="#000000" />
        </Canvas>
      </main>
    </div>
  );
}

// Sub-components
interface RoomProps {
  config: RoomConfig;
  showGrid: boolean;
  onDeselect: () => void;
}

const Room: React.FC<RoomProps> = ({ config, showGrid, onDeselect }) => {
  const { width, depth, height } = config;

  return (
    <group onPointerMissed={onDeselect}>
      {/* Floor */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} receiveShadow>
        <planeGeometry args={[width, depth]} />
        <meshStandardMaterial color="#f0f0f0" />
      </mesh>

      {/* Grid */}
      {showGrid && (
        <Grid 
          infiniteGrid 
          fadeDistance={50} 
          fadeStrength={5} 
          sectionSize={GRID_SIZE * 2} 
          cellSize={GRID_SIZE} 
          sectionColor="#3B82F6" 
          cellColor="#d1d5db" 
          position={[0, 0.01, 0]} 
        />
      )}

      {/* Walls (Simple plane representations) */}
      <group>
        {/* Back Wall */}
        <mesh position={[0, height / 2, -depth / 2]}>
          <planeGeometry args={[width, height]} />
          <meshStandardMaterial color="#ffffff" />
        </mesh>
        {/* Left Wall */}
        <mesh position={[-width / 2, height / 2, 0]} rotation={[0, Math.PI / 2, 0]}>
          <planeGeometry args={[depth, height]} />
          <meshStandardMaterial color="#ffffff" />
        </mesh>
        {/* Right Wall */}
        <mesh position={[width / 2, height / 2, 0]} rotation={[0, -Math.PI / 2, 0]}>
          <planeGeometry args={[depth, height]} />
          <meshStandardMaterial color="#ffffff" />
        </mesh>

        {/* Door Placeholder */}
        <mesh position={[-width / 2 + 0.1, 3.5, -depth / 4]} rotation={[0, Math.PI / 2, 0]}>
          <boxGeometry args={[3, 7, 0.1]} />
          <meshStandardMaterial color="#3E2723" />
        </mesh>

        {/* Window Placeholder */}
        <mesh position={[0, 5, depth / 2 - 0.05]} rotation={[0, Math.PI, 0]}>
          <boxGeometry args={[4, 3, 0.1]} />
          <meshStandardMaterial color="#E3F2FD" transparent opacity={0.5} />
        </mesh>
      </group>
    </group>
  );
};

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
}

const DraggableFurniture: React.FC<DraggableProps> = ({ item, selected, onSelect, onDrag }) => {
  const [isDragging, setIsDragging] = useState(false);
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
  };

  const handlePointerUp = () => {
    setIsDragging(false);
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging) return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
      onPointerLeave={handlePointerUp} // Clean up if mouse leaves canvas fast
    >
      <FurnitureModel type={item.type} selected={selected} />

      {/* Invisible larger hit area for easier dragging */}
      <mesh visible={false}>
        <boxGeometry args={[
          FURNITURE_DATA[item.type].dimensions.width, 
          FURNITURE_DATA[item.type].dimensions.height, 
          FURNITURE_DATA[item.type].dimensions.depth
        ]} />
      </mesh>

      {/* Selected Indicator */}
      {selected && (
        <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, 0.05, 0]}>
          <planeGeometry args={[
             FURNITURE_DATA[item.type].dimensions.width + 0.2, 
             FURNITURE_DATA[item.type].dimensions.depth + 0.2
          ]} />
          <meshBasicMaterial color="#3B82F6" transparent opacity={0.2} />
        </mesh>
      )}
    </group>
  );
};

