const LOCAL_STORAGE_KEY = 'hostel_planner_v2_cm';

const generateId = () => Math.random().toString(36).substr(2, 9);

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
  });

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed }));
      } catch (e) {
        console.error("Failed to load layout", e);
      }
    }
  }, []);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Layout saved successfully!");
  };

  const addItem = (type: FurnitureType) => {
    const data = FURNITURE_DATA[type];
    const currentCount = state.placedItems.filter(i => i.type === type).length;

    if (currentCount >= data.maxQuantity) {
      alert(`Max limit reached for ${data.name}.`);
      return;
    }

    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };

    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => 
        i.instanceId === state.selectedId 
          ? { ...i, rotation: i.rotation + Math.PI / 2 } 
          : i
      ),
    }));
  };

  const resetRoom = () => {
    if (confirm("Reset everything?")) {
      setState(prev => ({ ...prev, placedItems: [], selectedId: null }));
    }
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    const snappedPos: [number, number, number] = [
      Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE,
      0,
      Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE,
    ];

    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;
    const dims = FURNITURE_DATA[item.type].dimensions;
    const halfW = dims.width / 2;
    const halfD = dims.depth / 2;

    const limitX = state.room.width / 2;
    const limitZ = state.room.depth / 2;

    // Boundary constraints for main room
    snappedPos[0] = Math.max(-limitX + halfW, Math.min(limitX - halfW, snappedPos[0]));
    snappedPos[2] = Math.max(-limitZ + halfD, Math.min(limitZ - halfD, snappedPos[2]));

    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => 
        i.instanceId === id ? { ...i, position: snappedPos } : i
      ),
    }));
  }, [state.placedItems, state.room]);

  return (
    <div className="flex h-screen bg-neutral-900 flex-col md:flex-row overflow-hidden text-neutral-200">
