interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
}

const DraggableFurniture: React.FC<DraggableProps> = ({ item, selected, onSelect, onDrag }) => {
  const [isDragging, setIsDragging] = useState(false);
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
  };

  const handlePointerUp = () => setIsDragging(false);

  const handlePointerMove = (e: any) => {
    if (!isDragging) return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  const data = FURNITURE_DATA[item.type];

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
      onPointerLeave={handlePointerUp}
    >
      <FurnitureModel type={item.type} selected={selected} />

      {/* Outline for selection */}
      {selected && (
        <group position={[0, 0.01, 0]}>
           <mesh rotation={[-Math.PI/2, 0, 0]}>
              <planeGeometry args={[data.dimensions.width + 0.1, data.dimensions.depth + 0.1]} />
              <meshBasicMaterial color="#3B82F6" transparent opacity={0.3} side={THREE.DoubleSide} />
           </mesh>
        </group>
      )}

      {/* Hitbox */}
      <mesh visible={false}>
        <boxGeometry args={[data.dimensions.width, data.dimensions.height, data.dimensions.depth]} />
      </mesh>
    </group>
  );
};

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, ContactShadows, Environment } from '@react-three/drei';
import * as THREE from 'three';
import { INITIAL_ROOM, FURNITURE_DATA, GRID_SIZE } from './constants';
import { FurnitureType, PlacedItem, AppState, RoomConfig } from './types';
import { FurnitureModel } from './components/FurnitureModels';
import { Plus, Trash2, RotateCcw, Save, Grid3X3, Layers, Maximize, RotateCw } from 'lucide-react';

// Added interfaces for component props to fix missing type errors
interface RoomProps {
  config: RoomConfig;
  showGrid: boolean;
  onDeselect: () => void;
}

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
}

const LOCAL_STORAGE_KEY = 'hostel_planner_v2_cm';

const generateId = () => Math.random().toString(36).substr(2, 9);

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
  });

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed }));
      } catch (e) {
        console.error("Failed to load layout", e);
      }
    }
  }, []);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Layout saved successfully!");
  };

  const addItem = (type: FurnitureType) => {
    const data = FURNITURE_DATA[type];
    const currentCount = state.placedItems.filter(i => i.type === type).length;

    if (currentCount >= data.maxQuantity) {
      alert(`Max limit reached for ${data.name}.`);
      return;
    }

    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };

    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => 
        i.instanceId === state.selectedId 
          ? { ...i, rotation: i.rotation + Math.PI / 2 } 
          : i
      ),
    }));
  };

  const resetRoom = () => {
    if (confirm("Reset everything?")) {
      setState(prev => ({ ...prev, placedItems: [], selectedId: null }));
    }
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    const snappedPos: [number, number, number] = [
      Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE,
      0,
      Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE,
    ];

    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;
    const dims = FURNITURE_DATA[item.type].dimensions;
    const halfW = dims.width / 2;
    const halfD = dims.depth / 2;

    const limitX = state.room.width / 2;
    const limitZ = state.room.depth / 2;

    // Boundary constraints for main room
    snappedPos[0] = Math.max(-limitX + halfW, Math.min(limitX - halfW, snappedPos[0]));
    snappedPos[2] = Math.max(-limitZ + halfD, Math.min(limitZ - halfD, snappedPos[2]));

    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => 
        i.instanceId === id ? { ...i, position: snappedPos } : i
      ),
    }));
  }, [state.placedItems, state.room]);

  return (
    <div className="flex h-screen bg-neutral-900 flex-col md:flex-row overflow-hidden text-neutral-200">
      {/* Sidebar */}
      <aside className="w-full md:w-80 bg-neutral-800 border-r border-neutral-700 flex flex-col z-20 overflow-y-auto">
        <div className="p-6 border-b border-neutral-700 bg-neutral-900">
          <h1 className="text-xl font-bold text-white">Hostel3D Planner</h1>
          <p className="text-xs text-neutral-400 mt-1 uppercase tracking-widest font-semibold">Standard Layout Mode</p>
        </div>

        <div className="p-6 space-y-8 flex-1">
          <section>
            <h2 className="text-xs font-bold text-neutral-500 uppercase tracking-widest mb-4">Inventory</h2>
            <div className="grid grid-cols-1 gap-3">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                const count = state.placedItems.filter(i => i.type === type).length;
                const isLimit = count >= item.maxQuantity;

                return (
                  <button
                    key={type}
                    disabled={isLimit}
                    onClick={() => addItem(type)}
                    className={`flex items-center justify-between p-4 rounded-xl border transition-all ${
                      isLimit 
                      ? 'border-neutral-700 bg-neutral-800/50 text-neutral-600 cursor-not-allowed' 
                      : 'border-neutral-700 hover:border-blue-500 bg-neutral-700/30 hover:bg-neutral-700/50 text-neutral-200'
                    }`}
                  >
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-semibold text-sm">{item.name}</div>
                        <div className="text-[10px] text-neutral-500">
                          {Math.round(item.dimensions.width * 100)} x {Math.round(item.dimensions.depth * 100)} cm
                        </div>
                      </div>
                    </div>
                    <div className="flex flex-col items-end">
                       {!isLimit && <Plus size={16} className="text-blue-400" />}
                       <span className="text-[10px] mt-1 font-mono">{count}/{item.maxQuantity}</span>
                    </div>
                  </button>
                );
              })}
            </div>
          </section>

          {state.selectedId && (
            <section className="bg-blue-600/10 p-5 rounded-2xl border border-blue-500/30 animate-in fade-in zoom-in-95">
              <h3 className="text-xs font-bold text-blue-400 uppercase tracking-widest mb-4">Selected Item</h3>
              <div className="grid grid-cols-2 gap-2">
                <button 
                  onClick={rotateItem}
                  className="flex items-center justify-center space-x-2 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors shadow-lg shadow-blue-900/20"
                >
                  <RotateCw size={18} /> <span className="text-sm font-semibold">Rotate</span>
                </button>
                <button 
                  onClick={removeItem}
                  className="flex items-center justify-center space-x-2 py-3 bg-red-600/20 border border-red-500/50 text-red-400 rounded-lg hover:bg-red-600/30 transition-colors"
                >
                  <Trash2 size={18} /> <span className="text-sm font-semibold">Remove</span>
                </button>
              </div>
            </section>
          )}
        </div>

        <div className="p-6 border-t border-neutral-700 bg-neutral-900/50 space-y-3">
          <div className="grid grid-cols-2 gap-3">
            <button 
              onClick={saveLayout}
              className="flex items-center justify-center space-x-2 py-3 px-4 bg-neutral-100 text-neutral-900 rounded-xl font-bold hover:bg-white transition-all shadow-xl"
            >
              <Save size={18} /> <span>Save</span>
            </button>
            <button 
              onClick={resetRoom}
              className="flex items-center justify-center space-x-2 py-3 px-4 bg-neutral-800 text-neutral-400 rounded-xl hover:text-red-400 hover:bg-neutral-700 transition-all border border-neutral-700"
            >
              <RotateCcw size={18} /> <span>Reset</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Main Canvas Area */}
      <main className="flex-1 relative bg-neutral-950">
        <div className="absolute top-6 right-6 z-10 flex flex-col space-y-3">
          <button 
            onClick={() => setState(p => ({ ...p, showGrid: !p.showGrid }))}
            className={`p-4 rounded-2xl shadow-2xl transition-all border ${state.showGrid ? 'bg-blue-600 border-blue-400 text-white scale-110' : 'bg-neutral-800 border-neutral-700 text-neutral-400 hover:text-white'}`}
          >
            <Grid3X3 size={24} />
          </button>
          <button 
             onClick={() => setState(p => ({ ...p, is2D: !p.is2D }))}
             className={`p-4 rounded-2xl shadow-2xl transition-all border ${state.is2D ? 'bg-blue-600 border-blue-400 text-white scale-110' : 'bg-neutral-800 border-neutral-700 text-neutral-400 hover:text-white'}`}
          >
            {state.is2D ? <Maximize size={24} /> : <Layers size={24} />}
          </button>
        </div>

        <div className="absolute top-6 left-6 z-10 pointer-events-none">
          <div className="bg-neutral-900/80 backdrop-blur-md border border-neutral-700 px-5 py-3 rounded-2xl shadow-2xl">
             <p className="text-xs text-neutral-500 font-bold uppercase tracking-widest mb-1">Standard Room Dimensions</p>
             <p className="text-xl font-mono font-bold text-white">730 cm x 353 cm</p>
             <p className="text-[10px] text-blue-400 mt-2 font-semibold">1 unit = 100 cm (Snapping: 10cm)</p>
          </div>
        </div>

        <Canvas shadows dpr={[1, 2]}>
          <PerspectiveCamera 
            makeDefault 
            position={state.is2D ? [0, 15, 0] : [8, 8, 10]} 
            fov={state.is2D ? 40 : 50} 
          />

          <OrbitControls 
            enableRotate={!state.is2D} 
            maxPolarAngle={Math.PI / 2.2} 
            minDistance={3}
            maxDistance={25}
            makeDefault 
          />

          <ambientLight intensity={0.5} />
          <pointLight position={[5, 10, 5]} intensity={1.5} castShadow />
          <Environment preset="night" />

          {/* Room Environment matching the AutoCAD drawing */}
          <Room 
            config={state.room} 
            showGrid={state.showGrid} 
            onDeselect={() => setState(p => ({ ...p, selectedId: null }))}
          />

          {/* Furniture Instances */}
          {state.placedItems.map((item) => (
            <DraggableFurniture
              key={item.instanceId}
              item={item}
              selected={state.selectedId === item.instanceId}
              onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))}
              onDrag={(pos) => handleDrag(item.instanceId, pos)}
            />
          ))}

          <ContactShadows resolution={1024} scale={20} blur={2.5} opacity={0.6} far={10} color="#000000" />
        </Canvas>
      </main>
    </div>
  );
}

