      <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, -0.01, -depth/2 - bathDepth/2]}>
        <planeGeometry args={[width, bathDepth]} />
        <meshStandardMaterial color="#1a1a1a" />
      </mesh>
      <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, -0.01, -depth/2 - bathDepth - balconyDepth/2]}>
        <planeGeometry args={[width, balconyDepth]} />
        <meshStandardMaterial color="#050505" />
      </mesh>

      {/* TEXT LABELS */}
