import React, { useState, useEffect, useCallback, useMemo, memo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, ContactShadows, Environment, AdaptiveDpr, AdaptiveEvents, Text } from '@react-three/drei';
import * as THREE from 'three';
import { INITIAL_ROOM, FURNITURE_DATA, GRID_SIZE } from './constants';
import { FurnitureType, PlacedItem, AppState, RoomConfig } from './types';
import { FurnitureModel } from './components/FurnitureModels';
import { Plus, Trash2, RotateCcw, Save, Grid3X3, Layers, Maximize, RotateCw } from 'lucide-react';

const LOCAL_STORAGE_KEY = 'hostel_planner_v3_fixed';
const generateId = () => Math.random().toString(36).substr(2, 9);

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
}

const DraggableFurniture = memo(({ item, selected, onSelect, onDrag }: DraggableProps) => {
  const [isDragging, setIsDragging] = useState(false);
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
    e.target.setPointerCapture(e.pointerId);
  };

  const handlePointerUp = (e: any) => {
    setIsDragging(false);
    e.target.releasePointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging) return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  const data = FURNITURE_DATA[item.type];

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
    >
      <FurnitureModel type={item.type} selected={selected} />
      {selected && (
        <group position={[0, 0.01, 0]}>
           <mesh rotation={[-Math.PI/2, 0, 0]}>
              <planeGeometry args={[data.dimensions.width + 0.1, data.dimensions.depth + 0.1]} />
              <meshBasicMaterial color="#3B82F6" transparent opacity={0.3} side={THREE.DoubleSide} />
           </mesh>
        </group>
      )}
      <mesh visible={false}>
        <boxGeometry args={[data.dimensions.width, data.dimensions.height, data.dimensions.depth]} />
      </mesh>
    </group>
  );
});

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
  });

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed }));
      } catch (e) { console.error("Load failed", e); }
    }
  }, []);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Layout saved successfully!");
  };

  const addItem = (type: FurnitureType) => {
    const data = FURNITURE_DATA[type];
    const count = state.placedItems.filter(i => i.type === type).length;
    if (count >= data.maxQuantity) {
      alert(`Limit reached for ${data.name}`);
      return;
    }
    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0], // Starts at center of main room
      rotation: 0,
    };
    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => 
        i.instanceId === state.selectedId ? { ...i, rotation: i.rotation + Math.PI / 2 } : i
      ),
    }));
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    const snappedPos: [number, number, number] = [
      Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE,
      0,
      Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE,
    ];
    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;
    const dims = FURNITURE_DATA[item.type].dimensions;
    const limitX = state.room.width / 2;
    const limitZ = state.room.depth / 2;
    // Keep within main room boundaries only
    snappedPos[0] = Math.max(-limitX + dims.width/2, Math.min(limitX - dims.width/2, snappedPos[0]));
    snappedPos[2] = Math.max(-limitZ + dims.depth/2, Math.min(limitZ - dims.depth/2, snappedPos[2]));
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => i.instanceId === id ? { ...i, position: snappedPos } : i),
    }));
  }, [state.placedItems, state.room]);

  return (
    <div className="flex h-screen bg-[#0a0a0a] flex-col md:flex-row overflow-hidden text-neutral-200">
      <aside className="w-full md:w-80 bg-neutral-900 border-r border-neutral-800 flex flex-col z-20">
        <div className="p-6 border-b border-neutral-800 bg-black">
          <h1 className="text-xl font-bold text-white tracking-tight">Hostel Planner</h1>
          <p className="text-[10px] text-blue-500 font-bold uppercase mt-1">Room: 730 x 353 cm</p>
        </div>

        <div className="p-6 space-y-6 flex-1 overflow-y-auto">
          <section>
            <h2 className="text-[10px] font-black text-neutral-500 uppercase tracking-widest mb-4">Inventory</h2>
            <div className="space-y-2">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                const count = state.placedItems.filter(i => i.type === type).length;
                const isLimit = count >= item.maxQuantity;
                return (
                  <button key={type} disabled={isLimit} onClick={() => addItem(type)}
                    className={`w-full flex items-center justify-between p-3 rounded-xl border transition-all ${
                      isLimit ? 'border-neutral-800 bg-neutral-900/50 text-neutral-600' : 'border-neutral-800 bg-neutral-800/40 hover:border-blue-600'
                    }`}>
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-bold text-xs">{item.name}</div>
                        <div className="text-[9px] text-neutral-500">{Math.round(item.dimensions.width*100)}x{Math.round(item.dimensions.depth*100)} cm</div>
                      </div>
                    </div>
                    <span className="text-[10px] font-mono">{count}/{item.maxQuantity}</span>
                  </button>
                );
              })}
            </div>
          </section>

          {state.selectedId && (
            <section className="animate-in fade-in zoom-in-95 bg-blue-600/5 border border-blue-500/20 p-4 rounded-xl">
              <h3 className="text-[10px] font-bold text-blue-400 uppercase mb-3">Item Settings</h3>
              <div className="flex gap-2">
                <button onClick={rotateItem} className="flex-1 flex flex-col items-center justify-center p-2 bg-blue-600 rounded-lg text-white hover:bg-blue-700 transition-colors">
                  <RotateCw size={16} /><span className="text-[10px] font-bold mt-1">Rotate</span>
                </button>
                <button onClick={removeItem} className="flex-1 flex flex-col items-center justify-center p-2 bg-red-600/20 border border-red-500/30 text-red-500 rounded-lg hover:bg-red-600/30 transition-colors">
                  <Trash2 size={16} /><span className="text-[10px] font-bold mt-1">Delete</span>
                </button>
              </div>
            </section>
          )}
        </div>

        <div className="p-6 border-t border-neutral-800 bg-black/50 space-y-2">
          <button onClick={saveLayout} className="w-full flex items-center justify-center space-x-2 py-3 bg-white text-black rounded-xl font-bold hover:bg-neutral-200 transition-all">
            <Save size={18} /> <span>Save Layout</span>
          </button>
          <button onClick={() => confirm("Clear layout?") && setState(p => ({ ...p, placedItems: [], selectedId: null }))} className="w-full text-[10px] font-bold text-neutral-500 hover:text-red-400 py-1 uppercase tracking-tighter">
            Reset All
          </button>
        </div>
      </aside>

      <main className="flex-1 relative">
        <div className="absolute top-6 right-6 z-10 flex flex-col space-y-2">
          <button onClick={() => setState(p => ({ ...p, showGrid: !p.showGrid }))} className={`p-3 rounded-xl border ${state.showGrid ? 'bg-blue-600 text-white' : 'bg-neutral-900 text-neutral-400'}`}><Grid3X3 size={20}/></button>
          <button onClick={() => setState(p => ({ ...p, is2D: !p.is2D }))} className={`p-3 rounded-xl border ${state.is2D ? 'bg-blue-600 text-white' : 'bg-neutral-900 text-neutral-400'}`}>{state.is2D ? <Maximize size={20}/> : <Layers size={20}/>}</button>
        </div>

        <Canvas shadows={false} dpr={[1, 1.5]} gl={{ powerPreference: 'high-performance', antialias: false }}>
          <AdaptiveDpr pixelated />
          <AdaptiveEvents />
          <PerspectiveCamera makeDefault position={state.is2D ? [0, 15, 0] : [10, 10, 12]} fov={state.is2D ? 40 : 45} />
          <OrbitControls enableRotate={!state.is2D} maxPolarAngle={Math.PI / 2.1} makeDefault />
          <ambientLight intensity={0.8} />
          <pointLight position={[5, 10, 5]} intensity={1} />
          <Environment preset="night" />

          <RoomStructure showGrid={state.showGrid} config={state.room} onDeselect={() => setState(p => ({ ...p, selectedId: null }))} />

          {state.placedItems.map((item) => (
            <DraggableFurniture key={item.instanceId} item={item} selected={state.selectedId === item.instanceId} onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))} onDrag={(pos) => handleDrag(item.instanceId, pos)} />
          ))}

          <ContactShadows resolution={512} scale={25} blur={2} opacity={0.6} far={15} color="#000000" />
        </Canvas>
      </main>
    </div>
  );
}

