          <RoomStructure showGrid={state.showGrid} config={state.room} onDeselect={() => setState(p => ({ ...p, selectedId: null }))} />

          {state.placedItems.map((item) => (
            <DraggableFurniture key={item.instanceId} item={item} selected={state.selectedId === item.instanceId} onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))} onDrag={(pos) => handleDrag(item.instanceId, pos)} />
          ))}

          <ContactShadows resolution={512} scale={25} blur={2} opacity={0.6} far={15} color="#000000" />
        </Canvas>
      </main>
    </div>
  );
}

const RoomStructure = memo(({ config, showGrid, onDeselect }: { config: RoomConfig, showGrid: boolean, onDeselect: () => void }) => {
  const { width, depth, height } = config;
  const bathDepth = 1.25;
  const balconyDepth = 1.0;
  const wallThickness = 0.15;

  return (
    <group onPointerMissed={onDeselect}>
      {/* FLOORS */}
      <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, -0.01, 0]}>
        <planeGeometry args={[width, depth]} />
        <meshStandardMaterial color="#111" />
      </mesh>
      <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, -0.01, -depth/2 - bathDepth/2]}>
        <planeGeometry args={[width, bathDepth]} />
        <meshStandardMaterial color="#1a1a1a" />
      </mesh>
      <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, -0.01, -depth/2 - bathDepth - balconyDepth/2]}>
        <planeGeometry args={[width, balconyDepth]} />
        <meshStandardMaterial color="#050505" />
      </mesh>

      {/* TEXT LABELS */}
      {/* Fixed Text components by replacing 'opacity' with 'fillOpacity' which is valid for @react-three/drei Text */}
      <Text position={[0, 0.05, 0]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.3} color="white" fillOpacity={0.2} transparent>MAIN ROOM</Text>
      <Text position={[-width/4, 0.05, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="white" fillOpacity={0.2} transparent>BATHROOM</Text>
      <Text position={[width/4, 0.05, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="white" fillOpacity={0.2} transparent>TOILET</Text>
      <Text position={[0, 0.05, -depth/2 - bathDepth - balconyDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="white" fillOpacity={0.2} transparent>BALCONY</Text>

      {showGrid && (
        <Grid infiniteGrid fadeDistance={25} fadeStrength={5} sectionSize={1.0} cellSize={GRID_SIZE} sectionColor="#3B82F6" cellColor="#222" position={[0, 0.005, 0]} />
      )}

      {/* WALLS MATCHING AUTOCAD */}
      <group>
        {/* ENTRANCE WALL (BOTTOM) - 116cm Gap */}
        <mesh position={[- (width/2 + 0.58)/2, height/2, depth/2]}>
          <boxGeometry args={[width/2 - 0.58, height, wallThickness]} />
          <meshStandardMaterial color="#222" />
        </mesh>
        <mesh position={[ (width/2 + 0.58)/2, height/2, depth/2]}>
          <boxGeometry args={[width/2 - 0.58, height, wallThickness]} />
          <meshStandardMaterial color="#222" />
        </mesh>
        <Text position={[0, height + 0.2, depth/2]} fontSize={0.3} color="yellow">ENTRANCE D</Text>

        {/* SIDE WALLS */}
        <mesh position={[-width/2, height/2, 0]}>
          <boxGeometry args={[wallThickness, height, depth]} />
          <meshStandardMaterial color="#222" />
        </mesh>
        <mesh position={[width/2, height/2, 0]}>
          <boxGeometry args={[wallThickness, height, depth]} />
          <meshStandardMaterial color="#222" />
        </mesh>

        {/* ROOM TO BATH WALL - 150cm Gap */}
        <mesh position={[- (width/2 + 0.75)/2, height/2, -depth/2]}>
          <boxGeometry args={[width/2 - 0.75, height, wallThickness]} />
          <meshStandardMaterial color="#222" />
        </mesh>
        <mesh position={[ (width/2 + 0.75)/2, height/2, -depth/2]}>
          <boxGeometry args={[width/2 - 0.75, height, wallThickness]} />
          <meshStandardMaterial color="#222" />
        </mesh>

        {/* ANNEX SIDE WALLS */}
        <mesh position={[-width/2, height/2, -depth/2 - bathDepth/2]}>
          <boxGeometry args={[wallThickness, height, bathDepth]} />
          <meshStandardMaterial color="#222" />
        </mesh>
        <mesh position={[width/2, height/2, -depth/2 - bathDepth/2]}>
          <boxGeometry args={[wallThickness, height, bathDepth]} />
          <meshStandardMaterial color="#222" />
        </mesh>

        {/* BATH TO BALCONY WALL - 80cm Gap */}
        <mesh position={[- (width/2 + 0.4)/2, height/2, -depth/2 - bathDepth]}>
          <boxGeometry args={[width/2 - 0.4, height, wallThickness]} />
          <meshStandardMaterial color="#222" />
        </mesh>
        <mesh position={[ (width/2 + 0.4)/2, height/2, -depth/2 - bathDepth]}>
          <boxGeometry args={[width/2 - 0.4, height, wallThickness]} />
          <meshStandardMaterial color="#222" />
        </mesh>

        {/* BALCONY RAILING */}
        <mesh position={[0, 0.6, -depth/2 - bathDepth - balconyDepth]}>
          <boxGeometry args={[width, 1.2, 0.05]} />
          <meshStandardMaterial color="#333" transparent opacity={0.6} />
        </mesh>
      </group>
    </group>
  );
});

