const LOCAL_STORAGE_KEY = 'hostel_planner_v4_interior';
const generateId = () => Math.random().toString(36).substr(2, 9);

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
}

const DraggableFurniture = memo(({ item, selected, onSelect, onDrag }: DraggableProps) => {
  const [isDragging, setIsDragging] = useState(false);
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
    e.target.setPointerCapture(e.pointerId);
  };

  const handlePointerUp = (e: any) => {
    setIsDragging(false);
    e.target.releasePointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging) return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  const data = FURNITURE_DATA[item.type];

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
    >
      <FurnitureModel type={item.type} selected={selected} />
      {selected && (
        <group position={[0, 0.02, 0]}>
           <mesh rotation={[-Math.PI/2, 0, 0]}>
              <planeGeometry args={[data.dimensions.width + 0.1, data.dimensions.depth + 0.1]} />
              <meshBasicMaterial color="#3B82F6" transparent opacity={0.4} />
           </mesh>
        </group>
      )}
      <mesh visible={false}>
        <boxGeometry args={[data.dimensions.width, data.dimensions.height, data.dimensions.depth]} />
      </mesh>
    </group>
  );
});

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
  });

  const [theme, setTheme] = useState(THEMES.MODERN);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed }));
      } catch (e) { console.error("Load failed", e); }
    }
  }, []);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Room layout saved!");
  };

  const addItem = (type: FurnitureType) => {
    const data = FURNITURE_DATA[type];
    const count = state.placedItems.filter(i => i.type === type).length;
    if (count >= data.maxQuantity) {
      alert(`Limit reached for ${data.name}`);
      return;
    }
    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };
    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => 
        i.instanceId === state.selectedId ? { ...i, rotation: i.rotation + Math.PI / 2 } : i
      ),
    }));
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    const snappedPos: [number, number, number] = [
      Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE,
      0,
      Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE,
    ];
    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;
    const dims = FURNITURE_DATA[item.type].dimensions;
    const limitX = state.room.width / 2;
    const limitZ = state.room.depth / 2;

    snappedPos[0] = Math.max(-limitX + dims.width/2, Math.min(limitX - dims.width/2, snappedPos[0]));
    snappedPos[2] = Math.max(-limitZ + dims.depth/2, Math.min(limitZ - dims.depth/2, snappedPos[2]));
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => i.instanceId === id ? { ...i, position: snappedPos } : i),
    }));
  }, [state.placedItems, state.room]);

  return (
    <div className="flex h-screen bg-[#f3f4f6] flex-col md:flex-row overflow-hidden text-neutral-800 font-sans">
      {/* Sidebar UI */}
      <aside className="w-full md:w-80 bg-white border-r border-neutral-200 flex flex-col z-20 shadow-xl">
        <div className="p-6 border-b border-neutral-100 bg-neutral-50 flex items-center gap-3">
          <div className="p-2 bg-blue-600 rounded-lg text-white"><Home size={20}/></div>
          <div>
            <h1 className="text-lg font-bold text-neutral-900 tracking-tight leading-none">3D Room Planner</h1>
            <p className="text-[10px] text-neutral-500 font-bold uppercase mt-1 tracking-wider">Hostel Edition</p>
          </div>
        </div>

        <div className="p-6 space-y-8 flex-1 overflow-y-auto">
          {/* Customization Section */}
          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-4 flex items-center gap-2">
              <Palette size={12}/> Interior Design
            </h2>
            <div className="flex gap-2">
              {Object.entries(THEMES).map(([key, t]) => (
                <button
                  key={key}
                  onClick={() => setTheme(t)}
                  className={`flex-1 h-10 rounded-lg border-2 transition-all ${theme === t ? 'border-blue-500 shadow-md' : 'border-transparent hover:bg-neutral-100'}`}
                  style={{ backgroundColor: t.wall }}
                />
              ))}
            </div>
          </section>

          {/* Furniture Catalog */}
          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-4">Add Furniture</h2>
            <div className="grid grid-cols-1 gap-2">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                const count = state.placedItems.filter(i => i.type === type).length;
                const isLimit = count >= item.maxQuantity;
                return (
                  <button key={type} disabled={isLimit} onClick={() => addItem(type)}
                    className={`group flex items-center justify-between p-3 rounded-xl border transition-all ${
                      isLimit ? 'bg-neutral-50 border-neutral-100 text-neutral-300' : 'bg-white border-neutral-200 hover:border-blue-500 hover:shadow-lg'
                    }`}>
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl group-hover:scale-110 transition-transform">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-bold text-sm text-neutral-800">{item.name}</div>
                        <div className="text-[10px] text-neutral-500 font-mono">{Math.round(item.dimensions.width*100)}x{Math.round(item.dimensions.depth*100)}cm</div>
                      </div>
                    </div>
                    <div className="flex flex-col items-end">
                      {!isLimit && <Plus size={14} className="text-blue-500" />}
                      <span className="text-[9px] font-bold mt-1 text-neutral-400 bg-neutral-100 px-1.5 rounded">{count}/{item.maxQuantity}</span>
                    </div>
                  </button>
                );
