                  <RotateCw size={18} /><span className="text-[10px] font-black mt-1">ROTATE</span>
                </button>
                <button onClick={removeItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-white border border-red-200 text-red-500 rounded-xl hover:bg-red-50 hover:border-red-500 transition-all">
                  <Trash2 size={18} /><span className="text-[10px] font-black mt-1">REMOVE</span>
                </button>
