        <div className="absolute top-6 right-6 z-10 flex flex-col space-y-3">
          <button onClick={() => setState(p => ({ ...p, showGrid: !p.showGrid }))} className={`p-4 rounded-2xl shadow-2xl transition-all border ${state.showGrid ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-500'}`}>
            <Grid3X3 size={24}/>
          </button>
          <button onClick={() => setState(p => ({ ...p, is2D: !p.is2D }))} className={`p-4 rounded-2xl shadow-2xl transition-all border ${state.is2D ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-500'}`}>
            {state.is2D ? <Maximize size={24}/> : <Layers size={24}/>}
