        <div className="absolute bottom-6 left-6 z-10 bg-white/90 backdrop-blur-sm p-4 rounded-2xl border border-neutral-100 shadow-xl pointer-events-none">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-yellow-100 text-yellow-600 rounded-lg"><Sun size={16}/></div>
            <div>
              <p className="text-[10px] text-neutral-400 font-black uppercase tracking-widest">Room Canvas</p>
              <p className="text-sm font-bold text-neutral-800 leading-none">730 cm x 353 cm</p>
