          </div>
        </div>

        <Canvas shadows={false} dpr={[1, 1.5]} gl={{ powerPreference: 'high-performance', antialias: true }}>
          <AdaptiveDpr pixelated />
          <AdaptiveEvents />
          <PerspectiveCamera makeDefault position={state.is2D ? [0, 15, 0] : [8, 8, 10]} fov={state.is2D ? 45 : 50} />
          <OrbitControls enableRotate={!state.is2D} maxPolarAngle={Math.PI / 2.1} makeDefault minDistance={2} maxDistance={30} />

          <ambientLight intensity={1.2} />
          <hemisphereLight intensity={0.5} groundColor="#000000" />
          <directionalLight position={[10, 10, 10]} intensity={1.5} />
          <pointLight position={[-10, 5, -10]} intensity={0.5} />
          <Environment preset="apartment" />

          <RoomStructure theme={theme} showGrid={state.showGrid} config={state.room} onDeselect={() => setState(p => ({ ...p, selectedId: null }))} />

          {state.placedItems.map((item) => (
            <DraggableFurniture key={item.instanceId} item={item} selected={state.selectedId === item.instanceId} onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))} onDrag={(pos) => handleDrag(item.instanceId, pos)} />
          ))}

          <ContactShadows resolution={1024} scale={30} blur={2.5} opacity={0.4} far={20} color="#4b5563" />
        </Canvas>
      </main>
    </div>
  );
}

