import React, { useState, useEffect, useCallback, useMemo, memo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, ContactShadows, Environment, AdaptiveDpr, AdaptiveEvents, Text } from '@react-three/drei';
import * as THREE from 'three';
import { INITIAL_ROOM, FURNITURE_DATA, GRID_SIZE, THEMES } from './constants';
import { FurnitureType, PlacedItem, AppState, RoomConfig } from './types';
import { FurnitureModel } from './components/FurnitureModels';
import { Plus, Trash2, Save, Grid3X3, Layers, Maximize, RotateCw, Palette, Sun, Home, MousePointer2 } from 'lucide-react';

const LOCAL_STORAGE_KEY = 'hostel_planner_v5_fix';
const generateId = () => Math.random().toString(36).substr(2, 9);

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
  onDragStart: () => void;
  onDragEnd: () => void;
}

const DraggableFurniture = memo(({ item, selected, onSelect, onDrag, onDragStart, onDragEnd }: DraggableProps) => {
  const [isDragging, setIsDragging] = useState(false);
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
    onDragStart();
    e.target.setPointerCapture(e.pointerId);
  };

  const handlePointerUp = (e: any) => {
    setIsDragging(false);
    onDragEnd();
    e.target.releasePointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging) return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  const data = FURNITURE_DATA[item.type];

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
    >
      <FurnitureModel type={item.type} selected={selected} />

      {/* High-visibility selection base */}
      {selected && (
        <group position={[0, 0.01, 0]}>
           <mesh rotation={[-Math.PI/2, 0, 0]}>
              <planeGeometry args={[data.dimensions.width + 0.15, data.dimensions.depth + 0.15]} />
              <meshBasicMaterial color="#3B82F6" transparent opacity={0.5} />
           </mesh>
           <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, -0.005, 0]}>
              <planeGeometry args={[data.dimensions.width + 0.2, data.dimensions.depth + 0.2]} />
              <meshBasicMaterial color="white" transparent opacity={0.2} />
           </mesh>
        </group>
      )}

      {/* Interaction Proxy */}
      <mesh visible={false}>
        <boxGeometry args={[data.dimensions.width, data.dimensions.height, data.dimensions.depth]} />
      </mesh>
    </group>
  );
});

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
  });

  const [theme, setTheme] = useState(THEMES.MODERN);
  const [isDraggingAny, setIsDraggingAny] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed }));
      } catch (e) { console.error("Load failed", e); }
    }
  }, []);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Room layout saved!");
  };

  const addItem = (type: FurnitureType) => {
    const data = FURNITURE_DATA[type];
    const count = state.placedItems.filter(i => i.type === type).length;
    if (count >= data.maxQuantity) {
      alert(`Limit reached for ${data.name}`);
      return;
    }
    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };
    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => 
        i.instanceId === state.selectedId ? { ...i, rotation: i.rotation + Math.PI / 2 } : i
      ),
    }));
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    const snappedPos: [number, number, number] = [
      Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE,
      0,
      Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE,
    ];
    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;
    const dims = FURNITURE_DATA[item.type].dimensions;
    const limitX = state.room.width / 2;
    const limitZ = state.room.depth / 2;

    // Bounds check to keep furniture inside the main room area
    snappedPos[0] = Math.max(-limitX + dims.width/2, Math.min(limitX - dims.width/2, snappedPos[0]));
    snappedPos[2] = Math.max(-limitZ + dims.depth/2, Math.min(limitZ - dims.depth/2, snappedPos[2]));

    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => i.instanceId === id ? { ...i, position: snappedPos } : i),
    }));
  }, [state.placedItems, state.room]);

  return (
    <div className="flex h-screen bg-[#e2e8f0] flex-col md:flex-row overflow-hidden text-slate-800 font-sans">
      {/* Sidebar */}
      <aside className="w-full md:w-80 bg-white border-r border-slate-300 flex flex-col z-20 shadow-2xl">
        <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center gap-3">
          <div className="p-2 bg-blue-600 rounded-lg text-white shadow-lg shadow-blue-200"><Home size={20}/></div>
          <div>
            <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-none">DormDesigner</h1>
            <p className="text-[10px] text-slate-500 font-bold uppercase mt-1 tracking-wider">Hostel Planner</p>
          </div>
        </div>

        <div className="p-6 space-y-6 flex-1 overflow-y-auto">
          {/* Customization Section */}
          <section>
            <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
              <Palette size={12}/> Contrast Mode
            </h2>
            <div className="flex gap-2">
              {Object.entries(THEMES).map(([key, t]) => (
                <button
                  key={key}
                  title={key}
                  onClick={() => setTheme(t)}
                  className={`flex-1 h-12 rounded-xl border-4 transition-all overflow-hidden ${theme === t ? 'border-blue-500 shadow-inner scale-95' : 'border-slate-100 hover:border-slate-200'}`}
                >
                  <div className="w-full h-1/2" style={{ backgroundColor: t.wall }} />
                  <div className="w-full h-1/2" style={{ backgroundColor: t.floor }} />
                </button>
              ))}
            </div>
          </section>

          {/* Furniture Catalog */}
          <section>
            <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Add Furniture</h2>
            <div className="space-y-2">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                const count = state.placedItems.filter(i => i.type === type).length;
                const isLimit = count >= item.maxQuantity;
                return (
                  <button key={type} disabled={isLimit} onClick={() => addItem(type)}
                    className={`group w-full flex items-center justify-between p-3 rounded-xl border-2 transition-all ${
                      isLimit ? 'bg-slate-50 border-slate-100 text-slate-300' : 'bg-white border-slate-200 hover:border-blue-500 hover:bg-blue-50/30'
                    }`}>
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl transition-transform group-hover:scale-125">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-bold text-sm text-slate-800">{item.name}</div>
                        <div className="text-[10px] text-slate-500 font-mono">Size: {Math.round(item.dimensions.width*100)}x{Math.round(item.dimensions.depth*100)}cm</div>
                      </div>
                    </div>
                    <div className="bg-slate-100 px-2 py-1 rounded-lg text-[10px] font-black text-slate-500">
                      {count}/{item.maxQuantity}
                    </div>
                  </button>
                );
              })}
            </div>
          </section>

          {state.selectedId && (
            <section className="animate-in slide-in-from-bottom-2 p-4 bg-slate-900 rounded-2xl shadow-xl text-white">
              <h3 className="text-[10px] font-bold text-slate-400 uppercase mb-3 flex items-center gap-2">
                <MousePointer2 size={12}/> Edit Selected
              </h3>
              <div className="flex gap-2">
                <button onClick={rotateItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-blue-600 rounded-xl hover:bg-blue-500 transition-all">
                  <RotateCw size={18} /><span className="text-[10px] font-black mt-1">ROTATE</span>
                </button>
                <button onClick={removeItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-red-600 rounded-xl hover:bg-red-500 transition-all">
                  <Trash2 size={18} /><span className="text-[10px] font-black mt-1">REMOVE</span>
                </button>
              </div>
            </section>
          )}
        </div>

        <div className="p-6 border-t border-slate-100 bg-slate-50/50 space-y-3">
          <button onClick={saveLayout} className="w-full flex items-center justify-center space-x-2 py-4 bg-slate-900 text-white rounded-2xl font-bold hover:bg-black transition-all shadow-xl shadow-slate-200">
            <Save size={18} /> <span>Save Layout</span>
          </button>
          <button onClick={() => confirm("Reset room?") && setState(p => ({ ...p, placedItems: [], selectedId: null }))} className="w-full text-[10px] font-black text-slate-400 hover:text-red-500 py-1 transition-colors">
            FACTORY RESET
          </button>
        </div>
      </aside>

      <main className="flex-1 relative">
        {/* Floating Controls */}
        <div className="absolute top-6 right-6 z-10 flex flex-col space-y-2">
          <button onClick={() => setState(p => ({ ...p, showGrid: !p.showGrid }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.showGrid ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-slate-200 text-slate-400'}`}>
            <Grid3X3 size={24}/>
          </button>
          <button onClick={() => setState(p => ({ ...p, is2D: !p.is2D }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.is2D ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-slate-200 text-slate-400'}`}>
            {state.is2D ? <Maximize size={24}/> : <Layers size={24}/>}
          </button>
        </div>

        <div className="absolute top-6 left-6 z-10 bg-white/80 backdrop-blur-md p-4 rounded-2xl border-2 border-slate-200 shadow-xl pointer-events-none hidden md:block">
           <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1">Room Dimensions</p>
           <div className="flex items-center gap-3">
              <p className="text-lg font-black text-slate-800 leading-none tracking-tight">730 x 353 cm</p>
              <div className="h-4 w-[2px] bg-slate-300"/>
              <p className="text-[10px] font-bold text-blue-600">Snapping: 10cm</p>
           </div>
        </div>

        {/* Instructions */}
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-10 bg-slate-900/90 text-white px-6 py-2 rounded-full text-[11px] font-bold tracking-wide pointer-events-none shadow-2xl border border-white/10">
          {isDraggingAny ? "DRAGGING... CAMERA LOCKED" : "DRAG FURNITURE TO POSITION • CLICK TO SELECT"}
        </div>

        <Canvas shadows={false} dpr={[1, 1.5]} gl={{ powerPreference: 'high-performance', antialias: true }}>
          <AdaptiveDpr pixelated />
          <AdaptiveEvents />
          <PerspectiveCamera makeDefault position={state.is2D ? [0, 15, 0] : [10, 10, 10]} fov={state.is2D ? 45 : 50} />

          <OrbitControls 
            enabled={!isDraggingAny} // CRITICAL: Disable camera control while dragging
            enableRotate={!state.is2D} 
            maxPolarAngle={Math.PI / 2.1} 
            makeDefault 
            minDistance={2} 
            maxDistance={35} 
          />

          <ambientLight intensity={1.5} />
          <hemisphereLight intensity={0.6} groundColor="#000000" />
          <directionalLight position={[10, 15, 10]} intensity={2} />
          <Environment preset="night" />

          <RoomStructure theme={theme} showGrid={state.showGrid} config={state.room} onDeselect={() => setState(p => ({ ...p, selectedId: null }))} />

          {state.placedItems.map((item) => (
            <DraggableFurniture 
              key={item.instanceId} 
              item={item} 
              selected={state.selectedId === item.instanceId} 
              onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))} 
              onDrag={(pos) => handleDrag(item.instanceId, pos)}
              onDragStart={() => setIsDraggingAny(true)}
              onDragEnd={() => setIsDraggingAny(false)}
            />
          ))}

          <ContactShadows resolution={1024} scale={35} blur={3} opacity={0.6} far={20} color="#0f172a" />
        </Canvas>
      </main>
    </div>
  );
}

