import React, { useState, useEffect, useCallback, useMemo, memo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, ContactShadows, Environment, AdaptiveDpr, AdaptiveEvents, Text } from '@react-three/drei';
import * as THREE from 'three';
import { INITIAL_ROOM, FURNITURE_DATA, GRID_SIZE, THEMES } from './constants';
import { FurnitureType, PlacedItem, AppState, RoomConfig } from './types';
import { FurnitureModel } from './components/FurnitureModels';
import { Plus, Trash2, Save, Grid3X3, Layers, Maximize, RotateCw, Palette, Home, MousePointer2 } from 'lucide-react';

const LOCAL_STORAGE_KEY = 'hostel_planner_v6_realism';
const generateId = () => Math.random().toString(36).substr(2, 9);

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
  onDragStart: () => void;
  onDragEnd: () => void;
}

const DraggableFurniture = memo(({ item, selected, onSelect, onDrag, onDragStart, onDragEnd }: DraggableProps) => {
  const [isDragging, setIsDragging] = useState(false);
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
    onDragStart();
    e.target.setPointerCapture(e.pointerId);
  };

  const handlePointerUp = (e: any) => {
    setIsDragging(false);
    onDragEnd();
    e.target.releasePointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging) return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  const data = FURNITURE_DATA[item.type];

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
    >
      <FurnitureModel type={item.type} selected={selected} />
      {selected && (
        <group position={[0, 0.01, 0]}>
           <mesh rotation={[-Math.PI/2, 0, 0]}>
              <planeGeometry args={[data.dimensions.width + 0.15, data.dimensions.depth + 0.15]} />
              <meshBasicMaterial color="#3B82F6" transparent opacity={0.4} />
           </mesh>
        </group>
      )}
      <mesh visible={false}>
        <boxGeometry args={[data.dimensions.width, 2, data.dimensions.depth]} />
      </mesh>
    </group>
  );
});

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
  });

  const [theme, setTheme] = useState(THEMES.HOSTEL_STANDARD);
  const [isDraggingAny, setIsDraggingAny] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed }));
      } catch (e) { console.error("Load failed", e); }
    }
  }, []);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Room layout saved!");
  };

  const addItem = (type: FurnitureType) => {
    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };
    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => 
        i.instanceId === state.selectedId ? { ...i, rotation: i.rotation + Math.PI / 2 } : i
      ),
    }));
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    const snappedPos: [number, number, number] = [
      Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE,
      0,
      Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE,
    ];
    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;
    const dims = FURNITURE_DATA[item.type].dimensions;
    const limitX = state.room.width / 2;
    const limitZ = state.room.depth / 2;

    snappedPos[0] = Math.max(-limitX + dims.width/2, Math.min(limitX - dims.width/2, snappedPos[0]));
    snappedPos[2] = Math.max(-limitZ + dims.depth/2, Math.min(limitZ - dims.depth/2, snappedPos[2]));

    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => i.instanceId === id ? { ...i, position: snappedPos } : i),
    }));
  }, [state.placedItems, state.room]);

  return (
    <div className="flex h-screen bg-slate-100 flex-col md:flex-row overflow-hidden font-sans">
      <aside className="w-full md:w-80 bg-white border-r border-slate-200 flex flex-col z-20 shadow-xl">
        <div className="p-6 border-b border-slate-50 flex items-center gap-3 bg-slate-50">
          <div className="p-2 bg-blue-600 rounded-lg text-white shadow-lg shadow-blue-200"><Home size={20}/></div>
          <div>
            <h1 className="text-lg font-bold text-slate-900 tracking-tight leading-none">Hostel Planner</h1>
            <p className="text-[10px] text-slate-500 font-black uppercase mt-1 tracking-widest">3D Realism Mode</p>
          </div>
        </div>

        <div className="p-6 space-y-6 flex-1 overflow-y-auto">
          <section>
            <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
              <Palette size={12}/> Color Theme
            </h2>
            <div className="flex gap-2">
              {Object.entries(THEMES).map(([key, t]) => (
                <button
                  key={key}
                  onClick={() => setTheme(t)}
                  className={`flex-1 h-10 rounded-lg border-2 transition-all ${theme === t ? 'border-blue-500 scale-95 shadow-inner' : 'border-slate-100'}`}
                  style={{ backgroundColor: t.floor }}
                />
              ))}
            </div>
          </section>

          <section>
            <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Inventory</h2>
            <div className="space-y-2">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                const count = state.placedItems.filter(i => i.type === type).length;
                return (
                  <button key={type} onClick={() => addItem(type)}
                    className="group w-full flex items-center justify-between p-3 rounded-xl border-2 border-slate-100 bg-white hover:border-blue-500 hover:bg-blue-50/20 transition-all">
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl transition-transform group-hover:scale-125">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-bold text-sm text-slate-800">{item.name}</div>
                        <div className="text-[10px] text-slate-500">{Math.round(item.dimensions.width*100)}x{Math.round(item.dimensions.depth*100)}cm</div>
                      </div>
                    </div>
                    <div className="bg-slate-100 px-2 py-0.5 rounded text-[10px] font-bold text-slate-600">{count}</div>
                  </button>
                );
              })}
            </div>
          </section>

          {state.selectedId && (
            <section className="animate-in slide-in-from-bottom-2 p-4 bg-slate-900 rounded-2xl shadow-xl text-white">
              <h3 className="text-[10px] font-bold text-slate-400 uppercase mb-3 flex items-center gap-2">
                <MousePointer2 size={12}/> Selected Item
              </h3>
              <div className="flex gap-2">
                <button onClick={rotateItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-blue-600 rounded-xl hover:bg-blue-500 transition-all">
                  <RotateCw size={18} /><span className="text-[10px] font-black mt-1">ROTATE</span>
                </button>
                <button onClick={removeItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-red-600 rounded-xl hover:bg-red-500 transition-all">
                  <Trash2 size={18} /><span className="text-[10px] font-black mt-1">DELETE</span>
                </button>
              </div>
            </section>
          )}
        </div>

        <div className="p-6 border-t border-slate-100 space-y-3">
