const RoomStructure = memo(({ config, showGrid, onDeselect, theme }: { config: RoomConfig, showGrid: boolean, onDeselect: () => void, theme: any }) => {
  const { width, depth, height } = config;
  const bathDepth = 1.25;
  const balconyDepth = 1.0;
  const wallThickness = 0.2;

  // Realistic Tiled Floor Component
  const Tiles = ({ color, size, areaWidth, areaDepth, gap = 0.02 }: any) => {
    const tiles = [];
    const columns = Math.ceil(areaWidth / size);
    const rows = Math.ceil(areaDepth / size);
    for (let i = 0; i < columns; i++) {
      for (let j = 0; j < rows; j++) {
        tiles.push(
          <mesh key={`${i}-${j}`} position={[i * size - areaWidth/2 + size/2, -0.01, j * size - areaDepth/2 + size/2]} rotation={[-Math.PI/2, 0, 0]}>
            <planeGeometry args={[size - gap, size - gap]} />
            <meshStandardMaterial color={color} roughness={0.6} />
          </mesh>
        );
      }
    }
    return <group>{tiles}</group>;
  };

  return (
    <group onPointerMissed={onDeselect}>
      {/* MAIN ROOM TILES (Large White/Grey Tiles) */}
      <Tiles color={theme.floor} size={0.6} areaWidth={width} areaDepth={depth} />

      {/* BATHROOM TILES (Small Blue/Grey Tiles) */}
      <group position={[0, 0, -depth/2 - bathDepth/2]}>
        <Tiles color="#94a3b8" size={0.15} areaWidth={width} areaDepth={bathDepth} gap={0.01} />
      </group>

      {/* BALCONY FLOOR (Concrete/Stone) */}
      <mesh position={[0, -0.01, -depth/2 - bathDepth - balconyDepth/2]} rotation={[-Math.PI/2, 0, 0]}>
        <planeGeometry args={[width, balconyDepth]} />
        <meshStandardMaterial color="#64748b" roughness={1} />
      </mesh>

      {/* LABELS */}
      <group position={[0, 0.05, 0]}>
        <Text position={[0, 0, 0]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.3} color="#64748b" fillOpacity={0.3} fontWeight="bold">DORMITORY AREA</Text>
        <Text position={[-width/4, 0, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.15} color="#475569" fillOpacity={0.4}>SHOWER & TOILET</Text>
        <Text position={[width/4, 0, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.15} color="#475569" fillOpacity={0.4}>WASH AREA</Text>
      </group>

      {/* BATHROOM FIXTURES */}
      <group position={[-width/3.5, 0, -depth/2 - bathDepth/2]}>
         {/* Toilet */}
         <mesh position={[0, 0.2, 0.2]}>
            <boxGeometry args={[0.3, 0.4, 0.5]} />
            <meshStandardMaterial color="#fff" />
         </mesh>
         <mesh position={[0, 0.55, 0.4]}>
            <boxGeometry args={[0.35, 0.4, 0.15]} />
            <meshStandardMaterial color="#fff" />
         </mesh>
         {/* Shower Pipe */}
         <mesh position={[0, 2.2, -bathDepth/2 + 0.1]}>
            <cylinderGeometry args={[0.01, 0.01, 2.5]} />
            <meshStandardMaterial color="#94a3b8" metalness={1} />
         </mesh>
         <mesh position={[0, 2.4, -bathDepth/4]} rotation={[Math.PI/2, 0, 0]}>
            <cylinderGeometry args={[0.05, 0.02, 0.2]} />
            <meshStandardMaterial color="#94a3b8" metalness={1} />
         </mesh>
      </group>

      {/* WASH AREA FIXTURES */}
      <group position={[width/3.5, 0.8, -depth/2 - bathDepth/2]}>
         {/* Sink */}
         <mesh>
            <boxGeometry args={[0.4, 0.1, 0.3]} />
            <meshStandardMaterial color="#fff" />
         </mesh>
         <mesh position={[0, 0.1, -0.1]}>
            <cylinderGeometry args={[0.01, 0.01, 0.2]} />
            <meshStandardMaterial color="#94a3b8" metalness={1} />
         </mesh>
      </group>

      {showGrid && (
        <Grid infiniteGrid fadeDistance={25} fadeStrength={5} sectionSize={1} cellSize={GRID_SIZE} sectionColor={theme.accent} cellColor={theme.grid} position={[0, 0.01, 0]} />
      )}

      {/* SOLID WALLS */}
      <group>
        {/* ENTRANCE WALL (BOTTOM) - 116cm Gap */}
        <mesh position={[- (width/2 + 0.58)/2, height/2, depth/2]}>
          <boxGeometry args={[width/2 - 0.58, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[ (width/2 + 0.58)/2, height/2, depth/2]}>
          <boxGeometry args={[width/2 - 0.58, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* SIDE WALLS */}
        <mesh position={[-width/2, height/2, 0]}>
          <boxGeometry args={[wallThickness, height, depth]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[width/2, height/2, 0]}>
          <boxGeometry args={[wallThickness, height, depth]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* ROOM TO ANNEX WALL */}
        <mesh position={[- (width/2 + 0.75)/2, height/2, -depth/2]}>
          <boxGeometry args={[width/2 - 0.75, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[ (width/2 + 0.75)/2, height/2, -depth/2]}>
          <boxGeometry args={[width/2 - 0.75, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* ANNEX PARTITIONS */}
        <mesh position={[0, height/2, -depth/2 - bathDepth/2]}>
          <boxGeometry args={[wallThickness, height, bathDepth]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[-width/2, height/2, -depth/2 - bathDepth/2]}>
          <boxGeometry args={[wallThickness, height, bathDepth]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[width/2, height/2, -depth/2 - bathDepth/2]}>
          <boxGeometry args={[wallThickness, height, bathDepth]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* ANNEX TO BALCONY WALL */}
        <mesh position={[0, height/2, -depth/2 - bathDepth]}>
          <boxGeometry args={[width, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* BALCONY RAILING */}
        <mesh position={[0, 0.6, -depth/2 - bathDepth - balconyDepth]}>
          <boxGeometry args={[width, 1.2, 0.05]} />
          <meshStandardMaterial color="#475569" transparent opacity={0.6} />
        </mesh>
      </group>
    </group>
  );
});

import React, { useState, useEffect, useCallback, useMemo, memo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, ContactShadows, Environment, AdaptiveDpr, AdaptiveEvents, Text } from '@react-three/drei';
import * as THREE from 'three';
import { INITIAL_ROOM, FURNITURE_DATA, GRID_SIZE, THEMES } from './constants';
import { FurnitureType, PlacedItem, AppState, RoomConfig } from './types';
import { FurnitureModel } from './components/FurnitureModels';
import { Plus, Trash2, Save, Grid3X3, Layers, Maximize, RotateCw, Palette, Home, MousePointer2 } from 'lucide-react';

const LOCAL_STORAGE_KEY = 'hostel_planner_v7_optimized';
const generateId = () => Math.random().toString(36).substr(2, 9);

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
  onDragStart: () => void;
  onDragEnd: () => void;
}

const DraggableFurniture = memo(({ item, selected, onSelect, onDrag, onDragStart, onDragEnd }: DraggableProps) => {
  const [isDragging, setIsDragging] = useState(false);
  // Target floor plane for raycasting
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
    onDragStart();
    e.target.setPointerCapture(e.pointerId);
  };

  const handlePointerUp = (e: any) => {
    setIsDragging(false);
    onDragEnd();
    e.target.releasePointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging) return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    // Intersect ray with the ground plane
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  const data = FURNITURE_DATA[item.type];

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
    >
      <FurnitureModel type={item.type} selected={selected} />
      {selected && (
        <group position={[0, 0.01, 0]}>
           <mesh rotation={[-Math.PI/2, 0, 0]}>
              <planeGeometry args={[data.dimensions.width + 0.1, data.dimensions.depth + 0.1]} />
              <meshBasicMaterial color="#3B82F6" transparent opacity={0.3} />
           </mesh>
        </group>
      )}
      {/* Invisible collision/drag box */}
      <mesh visible={false}>
        <boxGeometry args={[data.dimensions.width, 2, data.dimensions.depth]} />
      </mesh>
    </group>
  );
});

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
  });

  const [theme, setTheme] = useState(THEMES.HOSTEL_STANDARD);
  const [isDraggingAny, setIsDraggingAny] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed }));
      } catch (e) { console.error("Load failed", e); }
    }
  }, []);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Layout saved successfully!");
  };

  const addItem = (type: FurnitureType) => {
    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };
    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => 
        i.instanceId === state.selectedId ? { ...i, rotation: i.rotation + Math.PI / 2 } : i
      ),
    }));
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    const snappedPos: [number, number, number] = [
      Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE,
      0,
      Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE,
    ];

    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;

    const dims = FURNITURE_DATA[item.type].dimensions;
    const padding = 0.05; // Stay slightly away from walls

    // CLAMPING BOUNDARIES to Dormitory area only
    const limitX = (state.room.width / 2) - (dims.width / 2) - padding;
    const limitZ = (state.room.depth / 2) - (dims.depth / 2) - padding;

    snappedPos[0] = Math.max(-limitX, Math.min(limitX, snappedPos[0]));
    snappedPos[2] = Math.max(-limitZ, Math.min(limitZ, snappedPos[2]));

    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => i.instanceId === id ? { ...i, position: snappedPos } : i),
    }));
  }, [state.placedItems, state.room]);

  return (
    <div className="flex h-screen bg-neutral-200 flex-col md:flex-row overflow-hidden font-sans select-none">
      <aside className="w-full md:w-80 bg-white border-r border-neutral-300 flex flex-col z-20 shadow-2xl">
        <div className="p-6 border-b border-neutral-100 flex items-center gap-3 bg-neutral-50">
          <div className="p-2 bg-blue-600 rounded-lg text-white"><Home size={20}/></div>
          <div>
            <h1 className="text-lg font-bold text-neutral-900 tracking-tight leading-none">DormPlanner</h1>
            <p className="text-[10px] text-neutral-500 font-black uppercase mt-1 tracking-widest">7.3m x 3.53m Room</p>
          </div>
        </div>

        <div className="p-6 space-y-6 flex-1 overflow-y-auto">
          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3 flex items-center gap-2">
              <Palette size={12}/> Ambience
            </h2>
            <div className="flex gap-2">
              {Object.entries(THEMES).map(([key, t]) => (
                <button
                  key={key}
                  onClick={() => setTheme(t)}
                  className={`flex-1 h-10 rounded-lg border-2 transition-all ${theme === t ? 'border-blue-500 scale-95 shadow-inner' : 'border-neutral-200'}`}
                  style={{ backgroundColor: t.floor }}
                />
              ))}
            </div>
          </section>

          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3">Add Items</h2>
            <div className="grid grid-cols-1 gap-2">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                return (
                  <button key={type} onClick={() => addItem(type)}
                    className="group w-full flex items-center justify-between p-3 rounded-xl border-2 border-neutral-100 bg-white hover:border-blue-500 hover:bg-blue-50 transition-all">
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl transition-transform group-hover:scale-110">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-bold text-sm text-neutral-800">{item.name}</div>
                        <div className="text-[10px] text-neutral-500">{Math.round(item.dimensions.width*100)}x{Math.round(item.dimensions.depth*100)}cm</div>
                      </div>
                    </div>
                    <Plus size={14} className="text-neutral-300 group-hover:text-blue-500" />
                  </button>
                );
              })}
            </div>
          </section>

          {state.selectedId && (
            <section className="animate-in slide-in-from-bottom-2 p-4 bg-neutral-900 rounded-2xl shadow-xl text-white">
              <h3 className="text-[10px] font-bold text-neutral-400 uppercase mb-3 flex items-center gap-2">
                <MousePointer2 size={12}/> Edit Item
              </h3>
              <div className="flex gap-2">
                <button onClick={rotateItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-blue-600 rounded-xl hover:bg-blue-500 transition-all">
                  <RotateCw size={18} /><span className="text-[10px] font-black mt-1 uppercase">Rotate</span>
                </button>
                <button onClick={removeItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-red-600 rounded-xl hover:bg-red-500 transition-all">
                  <Trash2 size={18} /><span className="text-[10px] font-black mt-1 uppercase">Delete</span>
                </button>
              </div>
            </section>
          )}
        </div>

        <div className="p-6 border-t border-neutral-100 space-y-3">
          <button onClick={saveLayout} className="w-full flex items-center justify-center space-x-2 py-4 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 transition-all shadow-xl">
            <Save size={18} /> <span>Save Layout</span>
          </button>
          <button onClick={() => confirm("Reset all furniture?") && setState(p => ({ ...p, placedItems: [], selectedId: null }))} className="w-full text-[10px] font-bold text-neutral-400 hover:text-red-500 py-1 transition-colors uppercase tracking-widest">
            Clear Room
          </button>
        </div>
      </aside>

      <main className="flex-1 relative bg-neutral-100">
        <div className="absolute top-6 right-6 z-10 flex flex-col space-y-2">
          <button onClick={() => setState(p => ({ ...p, showGrid: !p.showGrid }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.showGrid ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
            <Grid3X3 size={24}/>
          </button>
          <button onClick={() => setState(p => ({ ...p, is2D: !p.is2D }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.is2D ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
            {state.is2D ? <Maximize size={24}/> : <Layers size={24}/>}
          </button>
        </div>

        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-10 bg-neutral-900/90 text-white px-6 py-2 rounded-full text-[11px] font-bold tracking-widest pointer-events-none shadow-2xl border border-white/10 uppercase">
          {isDraggingAny ? "Placing..." : "Click & Drag items to move"}
        </div>

        <Canvas shadows dpr={[1, 1.5]} gl={{ antialias: true, powerPreference: 'high-performance' }}>
          <AdaptiveDpr pixelated />
          <AdaptiveEvents />
          <PerspectiveCamera makeDefault position={state.is2D ? [0, 15, 0] : [12, 10, 12]} fov={state.is2D ? 35 : 45} />

          <OrbitControls 
            enabled={!isDraggingAny}
            enableRotate={!state.is2D} 
            maxPolarAngle={Math.PI / 2.1} 
            makeDefault 
            minDistance={4} 
            maxDistance={30} 
            target={[0, 0, -1]}
          />

          <ambientLight intensity={0.8} />
          <directionalLight position={[10, 20, 10]} intensity={1.2} castShadow shadow-mapSize={[512, 512]} />
          <Environment preset="city" />

          <RoomStructure theme={theme} showGrid={state.showGrid} config={state.room} onDeselect={() => setState(p => ({ ...p, selectedId: null }))} />

          {state.placedItems.map((item) => (
            <DraggableFurniture 
              key={item.instanceId} 
              item={item} 
              selected={state.selectedId === item.instanceId} 
              onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))} 
              onDrag={(pos) => handleDrag(item.instanceId, pos)}
              onDragStart={() => setIsDraggingAny(true)}
              onDragEnd={() => setIsDraggingAny(false)}
            />
          ))}

          <ContactShadows resolution={512} scale={40} blur={2} opacity={0.4} far={15} color="#000000" />
        </Canvas>
      </main>
    </div>
  );
}

const RoomStructure = memo(({ config, showGrid, onDeselect, theme }: { config: RoomConfig, showGrid: boolean, onDeselect: () => void, theme: any }) => {
