const generateId = () => Math.random().toString(36).substr(2, 9);

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
  onDragStart: () => void;
  onDragEnd: () => void;
}

const DraggableFurniture = memo(({ item, selected, onSelect, onDrag, onDragStart, onDragEnd }: DraggableProps) => {
  const [isDragging, setIsDragging] = useState(false);
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
    onDragStart();
    e.target.setPointerCapture(e.pointerId);
  };

  const handlePointerUp = (e: any) => {
    setIsDragging(false);
    onDragEnd();
    e.target.releasePointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging) return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  const data = FURNITURE_DATA[item.type];

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
    >
      <FurnitureModel type={item.type} selected={selected} />
      {selected && (
        <group position={[0, 0.01, 0]}>
           <mesh rotation={[-Math.PI/2, 0, 0]}>
              <planeGeometry args={[data.dimensions.width + 0.05, data.dimensions.depth + 0.05]} />
              <meshBasicMaterial color="#3B82F6" transparent opacity={0.3} />
           </mesh>
        </group>
      )}
      <mesh visible={false}>
        <boxGeometry args={[data.dimensions.width, 2, data.dimensions.depth]} />
      </mesh>
    </group>
  );
});

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
  });

  const [theme, setTheme] = useState(THEMES.HOSTEL_STANDARD);
  const [isDraggingAny, setIsDraggingAny] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed }));
      } catch (e) { console.error("Load failed", e); }
    }
  }, []);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Layout saved successfully!");
  };

  const getEffectiveDims = useCallback((type: FurnitureType, rotation: number) => {
    const dims = FURNITURE_DATA[type].dimensions;
    const isRotated = Math.round(Math.abs(Math.sin(rotation))) === 1;
    return {
      w: isRotated ? dims.depth : dims.width,
      d: isRotated ? dims.width : dims.depth
    };
  }, []);

  const clampPosition = useCallback((pos: [number, number, number], type: FurnitureType, rotation: number): [number, number, number] => {
    const { w, d } = getEffectiveDims(type, rotation);
    const wallThick = 0.2; // Match wallThickness in RoomStructure

    // Limits based on room dimensions 7.3 x 3.53
    // Subtract half-width/depth of furniture plus wall padding
    const limitX = (state.room.width / 2) - (w / 2) - 0.02;
    const limitZ = (state.room.depth / 2) - (d / 2) - 0.02;

    return [
      Math.max(-limitX, Math.min(limitX, pos[0])),
      0,
      Math.max(-limitZ, Math.min(limitZ, pos[2])),
    ];
  }, [state.room, getEffectiveDims]);

  const addItem = (type: FurnitureType) => {
    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };
    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId) return;
    setState(prev => {
      const updatedItems = prev.placedItems.map(i => {
        if (i.instanceId === prev.selectedId) {
          const newRotation = i.rotation + Math.PI / 2;
          return { 
            ...i, 
            rotation: newRotation, 
            position: clampPosition(i.position, i.type, newRotation) 
          };
        }
        return i;
      });
      return { ...prev, placedItems: updatedItems };
    });
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;

    const snappedX = Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE;
    const snappedZ = Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE;

    const clampedPos = clampPosition([snappedX, 0, snappedZ], item.type, item.rotation);

    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => i.instanceId === id ? { ...i, position: clampedPos } : i),
    }));
  }, [state.placedItems, clampPosition]);

  return (
    <div className="flex h-screen bg-neutral-100 flex-col md:flex-row overflow-hidden font-sans select-none">
      <aside className="w-full md:w-80 bg-white border-r border-neutral-300 flex flex-col z-20 shadow-2xl">
        <div className="p-6 border-b border-neutral-100 flex items-center gap-3 bg-neutral-50">
          <div className="p-2 bg-blue-600 rounded-lg text-white shadow-lg shadow-blue-200"><Home size={20}/></div>
          <div>
            <h1 className="text-lg font-bold text-neutral-900 tracking-tight leading-none">DormPlanner</h1>
            <p className="text-[10px] text-neutral-500 font-black uppercase mt-1 tracking-widest">Blueprint Accurate</p>
          </div>
        </div>

        <div className="p-6 space-y-6 flex-1 overflow-y-auto">
          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3 flex items-center gap-2 text-center">
              <Palette size={12}/> Color Ambience
            </h2>
            <div className="flex gap-2">
              {Object.entries(THEMES).map(([key, t]) => (
                <button
                  key={key}
                  onClick={() => setTheme(t)}
                  className={`flex-1 h-10 rounded-lg border-2 transition-all ${theme === t ? 'border-blue-500 scale-95 shadow-inner' : 'border-neutral-200'}`}
                  style={{ backgroundColor: t.floor }}
                />
              ))}
            </div>
          </section>

          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3">Add Furniture</h2>
            <div className="grid grid-cols-1 gap-2">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                return (
                  <button key={type} onClick={() => addItem(type)}
                    className="group w-full flex items-center justify-between p-3 rounded-xl border-2 border-neutral-100 bg-white hover:border-blue-500 hover:bg-blue-50 transition-all">
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl transition-transform group-hover:scale-110">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-bold text-sm text-neutral-800">{item.name}</div>
                        <div className="text-[10px] text-neutral-500">{Math.round(item.dimensions.width*100)}x{Math.round(item.dimensions.depth*100)}cm</div>
                      </div>
                    </div>
                    <Plus size={14} className="text-neutral-300 group-hover:text-blue-500" />
                  </button>
                );
              })}
            </div>
          </section>

          {state.selectedId && (
            <section className="animate-in slide-in-from-bottom-2 p-4 bg-neutral-900 rounded-2xl shadow-xl text-white">
              <h3 className="text-[10px] font-bold text-neutral-400 uppercase mb-3 flex items-center gap-2">
                <MousePointer2 size={12}/> Modify Selection
              </h3>
              <div className="flex gap-2">
                <button onClick={rotateItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-blue-600 rounded-xl hover:bg-blue-500 transition-all">
                  <RotateCw size={18} /><span className="text-[10px] font-black mt-1 uppercase">Rotate</span>
                </button>
                <button onClick={removeItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-red-600 rounded-xl hover:bg-red-500 transition-all">
                  <Trash2 size={18} /><span className="text-[10px] font-black mt-1 uppercase">Remove</span>
                </button>
              </div>
            </section>
          )}
        </div>

        <div className="p-6 border-t border-neutral-100 space-y-3">
          <button onClick={saveLayout} className="w-full flex items-center justify-center space-x-2 py-4 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 transition-all shadow-xl">
            <Save size={18} /> <span>Save Layout</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 relative bg-neutral-100">
        <div className="absolute top-6 right-6 z-10 flex flex-col space-y-2">
          <button onClick={() => setState(p => ({ ...p, showGrid: !p.showGrid }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.showGrid ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
            <Grid3X3 size={24}/>
          </button>
          <button onClick={() => setState(p => ({ ...p, is2D: !p.is2D }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.is2D ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
            {state.is2D ? <Maximize size={24}/> : <Layers size={24}/>}
          </button>
        </div>

        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-10 bg-neutral-900/90 text-white px-6 py-2 rounded-full text-[11px] font-bold tracking-widest pointer-events-none shadow-2xl border border-white/10 uppercase">
          {isDraggingAny ? "Moving..." : "Drag furniture to start planning"}
        </div>

        <Canvas shadows dpr={[1, 1.5]} gl={{ antialias: true }}>
          <AdaptiveDpr pixelated />
          <AdaptiveEvents />
          <PerspectiveCamera makeDefault position={state.is2D ? [0, 15, 0] : [12, 12, 12]} fov={state.is2D ? 30 : 45} />

          <OrbitControls 
            enabled={!isDraggingAny}
            enableRotate={!state.is2D} 
            maxPolarAngle={Math.PI / 2.1} 
            makeDefault 
            minDistance={4} 
            maxDistance={40} 
            target={[0, 0, 0]}
          />

          <ambientLight intensity={0.9} />
          <directionalLight position={[10, 20, 10]} intensity={1.5} castShadow shadow-mapSize={[1024, 1024]} />
          <Environment preset="apartment" />

          <RoomStructure theme={theme} showGrid={state.showGrid} config={state.room} onDeselect={() => setState(p => ({ ...p, selectedId: null }))} />

          {state.placedItems.map((item) => (
            <DraggableFurniture 
              key={item.instanceId} 
              item={item} 
              selected={state.selectedId === item.instanceId} 
              onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))} 
              onDrag={(pos) => handleDrag(item.instanceId, pos)}
              onDragStart={() => setIsDraggingAny(true)}
              onDragEnd={() => setIsDraggingAny(false)}
            />
          ))}

          <ContactShadows resolution={1024} scale={50} blur={2.5} opacity={0.4} far={20} color="#000000" />
        </Canvas>
      </main>
    </div>
  );
}

const RoomStructure = memo(({ config, showGrid, onDeselect, theme }: { config: RoomConfig, showGrid: boolean, onDeselect: () => void, theme: any }) => {
  const { width, depth, height } = config;
  const bathDepth = 1.25; // 125cm
  const balconyDepth = 1.0;
  const wallThickness = 0.15;

  return (
    <group onPointerMissed={onDeselect}>
      {/* FLOORS */}
      {/* Main Room: 7.3m x 3.53m */}
      <mesh position={[0, -0.01, 0]} rotation={[-Math.PI/2, 0, 0]} receiveShadow>
        <planeGeometry args={[width, depth]} />
        <meshStandardMaterial color={theme.floor} roughness={0.7} />
      </mesh>

      {/* Bathroom/Toilet area: 7.3m x 1.25m */}
      <mesh position={[0, -0.01, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]}>
        <planeGeometry args={[width, bathDepth]} />
        <meshStandardMaterial color="#cbd5e1" roughness={0.8} />
      </mesh>

      {/* Balcony: 7.3m x 1.0m */}
      <mesh position={[0, -0.01, -depth/2 - bathDepth - balconyDepth/2]} rotation={[-Math.PI/2, 0, 0]}>
        <planeGeometry args={[width, balconyDepth]} />
        <meshStandardMaterial color="#475569" roughness={1} />
      </mesh>

      {/* LABELS FROM BLUEPRINT */}
      <group position={[0, 0.05, 0]}>
        <Text position={[-width/4, 0, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#1e293b" fillOpacity={0.5} fontWeight="bold">BATHROOM</Text>
        <Text position={[width/4, 0, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#1e293b" fillOpacity={0.5} fontWeight="bold">TOILET</Text>
        <Text position={[0, 0, -depth/2 - bathDepth - balconyDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#fff" fillOpacity={0.7} fontWeight="bold">BALCONY</Text>
        <Text position={[0, 0, depth/2 + 0.3]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.15} color="#1e293b" fillOpacity={0.8}>D (116cm)</Text>
      </group>

      {showGrid && (
        <Grid infiniteGrid fadeDistance={40} fadeStrength={5} sectionSize={1} cellSize={GRID_SIZE} sectionColor={theme.accent} cellColor={theme.grid} position={[0, 0.01, 0]} />
      )}

      {/* WALL SEGMENTS (Blue-print accurate centered openings) */}
      <group>
        {/* BOTTOM ENTRANCE WALL (116cm centered) */}
        {/* Total 7.3. Segment = (7.3 - 1.16)/2 = 3.07 */}
        <mesh position={[- (width/2 - 3.07/2), height/2, depth/2]}>
          <boxGeometry args={[3.07, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[ (width/2 - 3.07/2), height/2, depth/2]}>
          <boxGeometry args={[3.07, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* OUTER SIDE WALLS */}
        <mesh position={[-width/2, height/2, -bathDepth/2]}>
          <boxGeometry args={[wallThickness, height, depth + bathDepth]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[width/2, height/2, -bathDepth/2]}>
          <boxGeometry args={[wallThickness, height, depth + bathDepth]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* MIDDLE DIVIDER WALL (150cm centered) */}
        {/* Segment = (7.3 - 1.5)/2 = 2.9 */}
        <mesh position={[- (width/2 - 2.9/2), height/2, -depth/2]}>
          <boxGeometry args={[2.9, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[ (width/2 - 2.9/2), height/2, -depth/2]}>
          <boxGeometry args={[2.9, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* BALCONY ACCESS WALL (80cm centered) */}
        {/* Segment = (7.3 - 0.8)/2 = 3.25 */}
        <mesh position={[- (width/2 - 3.25/2), height/2, -depth/2 - bathDepth]}>
          <boxGeometry args={[3.25, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[ (width/2 - 3.25/2), height/2, -depth/2 - bathDepth]}>
          <boxGeometry args={[3.25, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* BALCONY RAILING (Outer edge) */}
        <mesh position={[0, 0.6, -depth/2 - bathDepth - balconyDepth]}>
          <boxGeometry args={[width, 1.2, 0.05]} />
          <meshStandardMaterial color="#475569" transparent opacity={0.6} />
        </mesh>
      </group>
    </group>
  );
});

import React, { useState, useEffect, useCallback, useMemo, memo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, ContactShadows, Environment, AdaptiveDpr, AdaptiveEvents, Text } from '@react-three/drei';
import * as THREE from 'three';
import { INITIAL_ROOM, FURNITURE_DATA, GRID_SIZE, THEMES } from './constants';
import { FurnitureType, PlacedItem, AppState, RoomConfig } from './types';
import { FurnitureModel } from './components/FurnitureModels';
import { Plus, Trash2, Save, Grid3X3, Layers, Maximize, RotateCw, Palette, Home, MousePointer2, AlertTriangle } from 'lucide-react';

const LOCAL_STORAGE_KEY = 'hostel_planner_v10_collision';
const generateId = () => Math.random().toString(36).substr(2, 9);

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  hasCollision: boolean;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
  onDragStart: () => void;
  onDragEnd: () => void;
}

const DraggableFurniture = memo(({ item, selected, hasCollision, onSelect, onDrag, onDragStart, onDragEnd }: DraggableProps) => {
  const [isDragging, setIsDragging] = useState(false);
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
    onDragStart();
    e.target.setPointerCapture(e.pointerId);
  };

  const handlePointerUp = (e: any) => {
    setIsDragging(false);
    onDragEnd();
    e.target.releasePointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging) return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  const data = FURNITURE_DATA[item.type];

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
    >
      <FurnitureModel type={item.type} selected={selected} hasCollision={hasCollision} />
      {selected && (
        <group position={[0, 0.01, 0]}>
           <mesh rotation={[-Math.PI/2, 0, 0]}>
              <planeGeometry args={[data.dimensions.width + 0.05, data.dimensions.depth + 0.05]} />
              <meshBasicMaterial color={hasCollision ? "#ef4444" : "#3B82F6"} transparent opacity={0.3} />
           </mesh>
        </group>
      )}
      <mesh visible={false}>
        <boxGeometry args={[data.dimensions.width, 2, data.dimensions.depth]} />
      </mesh>
    </group>
  );
});

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
  });

  const [theme, setTheme] = useState(THEMES.HOSTEL_STANDARD);
  const [isDraggingAny, setIsDraggingAny] = useState(false);
  const [collisions, setCollisions] = useState<Set<string>>(new Set());

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed }));
      } catch (e) { console.error("Load failed", e); }
    }
  }, []);

  const getEffectiveDims = useCallback((type: FurnitureType, rotation: number) => {
    const dims = FURNITURE_DATA[type].dimensions;
    const isRotated = Math.round(Math.abs(Math.sin(rotation))) === 1;
    return {
      w: isRotated ? dims.depth : dims.width,
      d: isRotated ? dims.width : dims.depth
    };
  }, []);

  // Simple AABB Collision Detection
  const checkCollisions = useCallback((items: PlacedItem[]) => {
    const collidingIds = new Set<string>();
    for (let i = 0; i < items.length; i++) {
      for (let j = i + 1; j < items.length; j++) {
        const a = items[i];
        const b = items[j];
        const dimA = getEffectiveDims(a.type, a.rotation);
        const dimB = getEffectiveDims(b.type, b.rotation);

        const overlapX = Math.abs(a.position[0] - b.position[0]) < (dimA.w + dimB.w) / 2;
        const overlapZ = Math.abs(a.position[2] - b.position[2]) < (dimA.d + dimB.d) / 2;

        if (overlapX && overlapZ) {
          collidingIds.add(a.instanceId);
          collidingIds.add(b.instanceId);
        }
      }
    }
    setCollisions(collidingIds);
  }, [getEffectiveDims]);

  useEffect(() => {
    checkCollisions(state.placedItems);
  }, [state.placedItems, checkCollisions]);

  const clampPosition = useCallback((pos: [number, number, number], type: FurnitureType, rotation: number): [number, number, number] => {
    const { w, d } = getEffectiveDims(type, rotation);
    const wallThick = 0.15;
    const bathDepth = 1.25;
    const balconyDepth = 1.0;

    // Safety padding for items that stick out (railings, brackets)
    const padding = 0.06;

    // Base Room Limits
    let minX = - (state.room.width / 2) + (w / 2) + padding;
    let maxX = (state.room.width / 2) - (w / 2) - padding;
    let minZ = - (state.room.depth / 2) + (d / 2) + padding;
    let maxZ = (state.room.depth / 2) - (d / 2) - padding;

    // Special Handling for Chairs (allowed in balcony via the centered path)
    if (type === 'CHAIR') {
      const isPathX = Math.abs(pos[0]) < (1.5 / 2 - w / 2); // 1.5m centered opening
      const isBalconyPathX = Math.abs(pos[0]) < (0.8 / 2 - w / 2); // 0.8m centered balcony opening

      if (isPathX) {
         // Allow passing into Annex
         minZ = - (state.room.depth / 2 + bathDepth) + (d / 2) + padding;

         if (isBalconyPathX) {
            // Allow passing into Balcony
            minZ = - (state.room.depth / 2 + bathDepth + balconyDepth) + (d / 2) + padding;
         }
      }
    }

    return [
      Math.max(minX, Math.min(maxX, pos[0])),
      0,
      Math.max(minZ, Math.min(maxZ, pos[2])),
    ];
  }, [state.room, getEffectiveDims]);

  const addItem = (type: FurnitureType) => {
    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };
    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId) return;
    setState(prev => {
      const updatedItems = prev.placedItems.map(i => {
        if (i.instanceId === prev.selectedId) {
          const newRotation = i.rotation + Math.PI / 2;
          return { 
            ...i, 
            rotation: newRotation, 
            position: clampPosition(i.position, i.type, newRotation) 
          };
        }
        return i;
      });
      return { ...prev, placedItems: updatedItems };
    });
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;

    const snappedX = Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE;
    const snappedZ = Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE;

    const clampedPos = clampPosition([snappedX, 0, snappedZ], item.type, item.rotation);

    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => i.instanceId === id ? { ...i, position: clampedPos } : i),
    }));
  }, [state.placedItems, clampPosition]);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Layout saved!");
  };

  return (
    <div className="flex h-screen bg-neutral-100 flex-col md:flex-row overflow-hidden font-sans select-none">
      <aside className="w-full md:w-80 bg-white border-r border-neutral-300 flex flex-col z-20 shadow-2xl">
        <div className="p-6 border-b border-neutral-100 flex items-center gap-3 bg-neutral-50">
          <div className="p-2 bg-blue-600 rounded-lg text-white"><Home size={20}/></div>
          <div>
            <h1 className="text-lg font-bold text-neutral-900 tracking-tight leading-none">DormPlanner</h1>
            <p className="text-[10px] text-neutral-500 font-black uppercase mt-1 tracking-widest">v1.2 Advanced</p>
          </div>
        </div>

        <div className="p-6 space-y-6 flex-1 overflow-y-auto">
          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3 flex items-center gap-2">
              <Palette size={12}/> Appearance
            </h2>
            <div className="flex gap-2">
              {Object.entries(THEMES).map(([key, t]) => (
                <button
                  key={key}
                  onClick={() => setTheme(t)}
                  className={`flex-1 h-10 rounded-lg border-2 transition-all ${theme === t ? 'border-blue-500 scale-95 shadow-inner' : 'border-neutral-200'}`}
                  style={{ backgroundColor: t.floor }}
                />
              ))}
            </div>
          </section>

          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3">Inventory</h2>
            <div className="grid grid-cols-1 gap-2">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                return (
                  <button key={type} onClick={() => addItem(type)}
                    className="group w-full flex items-center justify-between p-3 rounded-xl border-2 border-neutral-100 bg-white hover:border-blue-500 hover:bg-blue-50 transition-all">
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl transition-transform group-hover:scale-110">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-bold text-sm text-neutral-800">{item.name}</div>
                        <div className="text-[10px] text-neutral-500">{Math.round(item.dimensions.width*100)}x{Math.round(item.dimensions.depth*100)}cm</div>
                      </div>
                    </div>
                    <Plus size={14} className="text-neutral-300 group-hover:text-blue-500" />
                  </button>
                );
              })}
            </div>
          </section>

          {state.selectedId && (
            <section className="animate-in slide-in-from-bottom-2 p-4 bg-neutral-900 rounded-2xl shadow-xl text-white">
              <div className="flex items-center justify-between mb-3">
                 <h3 className="text-[10px] font-bold text-neutral-400 uppercase flex items-center gap-2">
                  <MousePointer2 size={12}/> Edit Selection
                </h3>
                {collisions.has(state.selectedId) && (
                  <div className="flex items-center gap-1 text-red-400 text-[10px] font-bold">
                    <AlertTriangle size={12} /> Overlap
                  </div>
                )}
              </div>
              <div className="flex gap-2">
                <button onClick={rotateItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-blue-600 rounded-xl hover:bg-blue-500 transition-all">
                  <RotateCw size={18} /><span className="text-[10px] font-black mt-1 uppercase">Rotate</span>
                </button>
                <button onClick={removeItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-red-600 rounded-xl hover:bg-red-500 transition-all">
                  <Trash2 size={18} /><span className="text-[10px] font-black mt-1 uppercase">Delete</span>
                </button>
              </div>
            </section>
          )}
        </div>

        <div className="p-6 border-t border-neutral-100">
          <button onClick={saveLayout} className="w-full flex items-center justify-center space-x-2 py-4 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 transition-all shadow-xl">
            <Save size={18} /> <span>Save Layout</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 relative bg-neutral-100">
        <div className="absolute top-6 right-6 z-10 flex flex-col space-y-2">
          <button onClick={() => setState(p => ({ ...p, showGrid: !p.showGrid }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.showGrid ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
            <Grid3X3 size={24}/>
          </button>
          <button onClick={() => setState(p => ({ ...p, is2D: !p.is2D }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.is2D ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
            {state.is2D ? <Maximize size={24}/> : <Layers size={24}/>}
          </button>
        </div>

        <Canvas shadows dpr={[1, 1.5]} gl={{ antialias: true }}>
          <AdaptiveDpr pixelated />
          <AdaptiveEvents />
          <PerspectiveCamera makeDefault position={state.is2D ? [0, 15, 0] : [10, 10, 10]} fov={state.is2D ? 30 : 45} />

          <OrbitControls 
            enabled={!isDraggingAny}
            enableRotate={!state.is2D} 
            maxPolarAngle={Math.PI / 2.1} 
            makeDefault 
            minDistance={4} 
            maxDistance={40} 
            target={[0, 0, 0]}
          />

          <ambientLight intensity={0.9} />
          <directionalLight position={[10, 20, 10]} intensity={1.5} castShadow shadow-mapSize={[1024, 1024]} />
          <Environment preset="apartment" />

          <RoomStructure theme={theme} showGrid={state.showGrid} config={state.room} onDeselect={() => setState(p => ({ ...p, selectedId: null }))} />

          {state.placedItems.map((item) => (
            <DraggableFurniture 
              key={item.instanceId} 
              item={item} 
              selected={state.selectedId === item.instanceId} 
              hasCollision={collisions.has(item.instanceId)}
              onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))} 
              onDrag={(pos) => handleDrag(item.instanceId, pos)}
              onDragStart={() => setIsDraggingAny(true)}
              onDragEnd={() => setIsDraggingAny(false)}
            />
          ))}

          <ContactShadows resolution={1024} scale={50} blur={2.5} opacity={0.4} far={20} color="#000000" />
        </Canvas>
      </main>
    </div>
  );
}

const RoomStructure = memo(({ config, showGrid, onDeselect, theme }: { config: RoomConfig, showGrid: boolean, onDeselect: () => void, theme: any }) => {
  const { width, depth, height } = config;
  const bathDepth = 1.25;
  const balconyDepth = 1.0;
  const wallThickness = 0.15;

  return (
    <group onPointerMissed={onDeselect}>
      {/* FLOORS */}
      <mesh position={[0, -0.01, 0]} rotation={[-Math.PI/2, 0, 0]} receiveShadow>
        <planeGeometry args={[width, depth]} />
        <meshStandardMaterial color={theme.floor} roughness={0.7} />
      </mesh>

      <mesh position={[0, -0.01, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]}>
        <planeGeometry args={[width, bathDepth]} />
        <meshStandardMaterial color="#cbd5e1" roughness={0.8} />
      </mesh>

      <mesh position={[0, -0.01, -depth/2 - bathDepth - balconyDepth/2]} rotation={[-Math.PI/2, 0, 0]}>
        <planeGeometry args={[width, balconyDepth]} />
        <meshStandardMaterial color="#475569" roughness={1} />
      </mesh>

      {/* LABELS */}
      <group position={[0, 0.05, 0]}>
        <Text position={[-width/4, 0, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#1e293b" fillOpacity={0.5} fontWeight="bold">BATHROOM</Text>
        <Text position={[width/4, 0, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#1e293b" fillOpacity={0.5} fontWeight="bold">TOILET</Text>
        <Text position={[0, 0, -depth/2 - bathDepth - balconyDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#fff" fillOpacity={0.7} fontWeight="bold">BALCONY</Text>
      </group>

      {showGrid && (
        <Grid infiniteGrid fadeDistance={40} fadeStrength={5} sectionSize={1} cellSize={GRID_SIZE} sectionColor={theme.accent} cellColor={theme.grid} position={[0, 0.01, 0]} />
      )}

      {/* WALL SEGMENTS */}
      <group>
        <mesh position={[- (width/2 - 3.07/2), height/2, depth/2]}>
          <boxGeometry args={[3.07, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[ (width/2 - 3.07/2), height/2, depth/2]}>
          <boxGeometry args={[3.07, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        <mesh position={[-width/2, height/2, -bathDepth/2]}>
          <boxGeometry args={[wallThickness, height, depth + bathDepth]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[width/2, height/2, -bathDepth/2]}>
          <boxGeometry args={[wallThickness, height, depth + bathDepth]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        <mesh position={[- (width/2 - 2.9/2), height/2, -depth/2]}>
          <boxGeometry args={[2.9, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[ (width/2 - 2.9/2), height/2, -depth/2]}>
          <boxGeometry args={[2.9, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        <mesh position={[- (width/2 - 3.25/2), height/2, -depth/2 - bathDepth]}>
          <boxGeometry args={[3.25, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[ (width/2 - 3.25/2), height/2, -depth/2 - bathDepth]}>
          <boxGeometry args={[3.25, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        <mesh position={[0, 0.6, -depth/2 - bathDepth - balconyDepth]}>
          <boxGeometry args={[width, 1.2, 0.05]} />
          <meshStandardMaterial color="#475569" transparent opacity={0.6} />
        </mesh>
      </group>
    </group>
  );
});

import React from 'react';
import { FurnitureType } from '../types';
import { FURNITURE_DATA } from '../constants';

interface ModelProps {
  type: FurnitureType;
  selected?: boolean;
  hasCollision?: boolean;
}

export const FurnitureModel: React.FC<ModelProps> = ({ type, selected, hasCollision }) => {
  const data = FURNITURE_DATA[type];
  const { width, height, depth } = data.dimensions;

  const baseMaterialProps = {
    color: hasCollision ? '#ef4444' : (selected ? '#3B82F6' : data.color),
    roughness: 0.4,
    metalness: 0.6,
  };

  switch (type) {
    case 'BUNKER_BED':
      return (
        <group>
          {/* Main frame posts - pulled slightly inward to avoid wall bleed */}
          {[[-1, -1], [-1, 1], [1, -1], [1, 1]].map(([x, z], i) => (
            <mesh key={i} position={[(x * (width - 0.04)) / 2, 0.9, (z * (depth - 0.04)) / 2]}>
              <boxGeometry args={[0.04, 1.8, 0.04]} />
              <meshStandardMaterial {...baseMaterialProps} />
            </mesh>
          ))}
          {/* Bunk Frames */}
          <mesh position={[0, 0.4, 0]}><boxGeometry args={[width - 0.02, 0.05, depth - 0.02]} /><meshStandardMaterial {...baseMaterialProps} /></mesh>
          <mesh position={[0, 1.4, 0]}><boxGeometry args={[width - 0.02, 0.05, depth - 0.02]} /><meshStandardMaterial {...baseMaterialProps} /></mesh>
          {/* Mattresses */}
          <mesh position={[0, 0.5, 0]}><boxGeometry args={[width - 0.06, 0.12, depth - 0.06]} /><meshStandardMaterial color="#f8fafc" /></mesh>
          <mesh position={[0, 1.5, 0]}><boxGeometry args={[width - 0.06, 0.12, depth - 0.06]} /><meshStandardMaterial color="#f8fafc" /></mesh>
          {/* Railings top bunk - ensured thickness doesn't exceed bounding box */}
          <mesh position={[0, 1.7, depth/2 - 0.01]}><boxGeometry args={[width - 0.02, 0.1, 0.02]} /><meshStandardMaterial {...baseMaterialProps} /></mesh>
          <mesh position={[0, 1.7, -depth/2 + 0.01]}><boxGeometry args={[width - 0.02, 0.1, 0.02]} /><meshStandardMaterial {...baseMaterialProps} /></mesh>
        </group>
      );

    case 'STUDY_TABLE':
      return (
        <group position={[0, 0.75, 0]}>
          {/* Table top */}
          <mesh>
            <boxGeometry args={[width - 0.02, 0.03, depth - 0.02]} />
            <meshStandardMaterial color="#cbd5e1" roughness={0.3} />
          </mesh>
          {/* Wall Brackets - tucked inside the bounding box */}
          <mesh position={[0, -0.1, -depth/2 + 0.04]} rotation={[0, 0, 0]}>
            <boxGeometry args={[width * 0.7, 0.02, 0.08]} />
            <meshStandardMaterial color="#475569" metalness={0.8} />
          </mesh>
          <group position={[0, -0.15, -depth/2 + 0.04]}>
             <mesh position={[-width/4, 0, 0]} rotation={[Math.PI/4, 0, 0]}>
                <boxGeometry args={[0.02, 0.25, 0.02]} />
                <meshStandardMaterial color="#64748b" />
             </mesh>
             <mesh position={[width/4, 0, 0]} rotation={[Math.PI/4, 0, 0]}>
                <boxGeometry args={[0.02, 0.25, 0.02]} />
                <meshStandardMaterial color="#64748b" />
             </mesh>
          </group>
        </group>
      );

    case 'BERO':
      return (
        <group>
          <mesh position={[0, 0.95, 0]}>
            <boxGeometry args={[width - 0.02, 1.9, depth - 0.02]} />
            <meshStandardMaterial {...baseMaterialProps} />
          </mesh>
          <mesh position={[0, 0.95, depth / 2 - 0.01]}>
            <boxGeometry args={[0.01, 1.8, 0.01]} />
            <meshStandardMaterial color="#1e293b" />
          </mesh>
          <mesh position={[-0.05, 1, depth / 2 - 0.01]}>
            <boxGeometry args={[0.02, 0.15, 0.02]} />
            <meshStandardMaterial color="#94a3b8" metalness={1} />
          </mesh>
          <mesh position={[0.05, 1, depth / 2 - 0.01]}>
            <boxGeometry args={[0.02, 0.15, 0.02]} />
            <meshStandardMaterial color="#94a3b8" metalness={1} />
          </mesh>
        </group>
      );

    case 'CHAIR':
      return (
        <group>
          <mesh position={[0, 0.45, 0]}>
            <boxGeometry args={[width - 0.02, 0.05, depth - 0.02]} />
            <meshStandardMaterial {...baseMaterialProps} />
          </mesh>
          <mesh position={[0, 0.75, -depth / 2 + 0.02]}>
            <boxGeometry args={[width - 0.02, 0.6, 0.04]} />
            <meshStandardMaterial {...baseMaterialProps} />
          </mesh>
          {[[-1, -1], [-1, 1], [1, -1], [1, 1]].map(([x, z], i) => (
            <mesh key={i} position={[(x * width) / 2.3, 0.22, (z * depth) / 2.3]}>
              <boxGeometry args={[0.03, 0.44, 0.03]} />
              <meshStandardMaterial color="#0f172a" />
            </mesh>
          ))}
        </group>
      );

    default:
      return null;
  }
};

import React, { useState, useEffect, useCallback, useMemo, memo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, ContactShadows, Environment, AdaptiveDpr, AdaptiveEvents, Text } from '@react-three/drei';
import * as THREE from 'three';
import { INITIAL_ROOM, FURNITURE_DATA, GRID_SIZE, THEMES } from './constants';
import { FurnitureType, PlacedItem, AppState, RoomConfig } from './types';
import { FurnitureModel } from './components/FurnitureModels';
import { Plus, Trash2, Save, Grid3X3, Layers, Maximize, RotateCw, Palette, Home, MousePointer2, AlertTriangle } from 'lucide-react';

const LOCAL_STORAGE_KEY = 'hostel_planner_v11_final';
const generateId = () => Math.random().toString(36).substr(2, 9);

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  hasCollision: boolean;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
  onDragStart: () => void;
  onDragEnd: () => void;
}

const DraggableFurniture = memo(({ item, selected, hasCollision, onSelect, onDrag, onDragStart, onDragEnd }: DraggableProps) => {
  const [isDragging, setIsDragging] = useState(false);
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
    onDragStart();
    e.target.setPointerCapture(e.pointerId);
  };

  const handlePointerUp = (e: any) => {
    setIsDragging(false);
    onDragEnd();
    e.target.releasePointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging) return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  const data = FURNITURE_DATA[item.type];

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
    >
      <FurnitureModel type={item.type} selected={selected} hasCollision={hasCollision} />
      {selected && (
        <group position={[0, 0.01, 0]}>
           <mesh rotation={[-Math.PI/2, 0, 0]}>
              <planeGeometry args={[data.dimensions.width + 0.05, data.dimensions.depth + 0.05]} />
              <meshBasicMaterial color={hasCollision ? "#ef4444" : "#3B82F6"} transparent opacity={0.3} />
           </mesh>
        </group>
      )}
      <mesh visible={false}>
        <boxGeometry args={[data.dimensions.width, 2, data.dimensions.depth]} />
      </mesh>
    </group>
  );
});

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
  });

  const [theme, setTheme] = useState(THEMES.HOSTEL_STANDARD);
  const [isDraggingAny, setIsDraggingAny] = useState(false);
  const [collisions, setCollisions] = useState<Set<string>>(new Set());

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed }));
      } catch (e) { console.error("Load failed", e); }
    }
  }, []);

  const getEffectiveDims = useCallback((type: FurnitureType, rotation: number) => {
    const dims = FURNITURE_DATA[type].dimensions;
    const isRotated = Math.round(Math.abs(Math.sin(rotation))) === 1;
    return {
      w: isRotated ? dims.depth : dims.width,
      d: isRotated ? dims.width : dims.depth
    };
  }, []);

  const checkCollisions = useCallback((items: PlacedItem[]) => {
    const collidingIds = new Set<string>();
    for (let i = 0; i < items.length; i++) {
      for (let j = i + 1; j < items.length; j++) {
        const a = items[i];
        const b = items[j];
        const dimA = getEffectiveDims(a.type, a.rotation);
        const dimB = getEffectiveDims(b.type, b.rotation);

        // Use a slightly smaller hit box (0.01m) to avoid floating point issues with perfect alignment
        const padding = 0.005;
        const overlapX = Math.abs(a.position[0] - b.position[0]) < (dimA.w + dimB.w) / 2 - padding;
        const overlapZ = Math.abs(a.position[2] - b.position[2]) < (dimA.d + dimB.d) / 2 - padding;

        if (overlapX && overlapZ) {
          collidingIds.add(a.instanceId);
          collidingIds.add(b.instanceId);
        }
      }
    }
    setCollisions(collidingIds);
  }, [getEffectiveDims]);

  useEffect(() => {
    checkCollisions(state.placedItems);
  }, [state.placedItems, checkCollisions]);

  const clampPosition = useCallback((pos: [number, number, number], type: FurnitureType, rotation: number): [number, number, number] => {
    const { w, d } = getEffectiveDims(type, rotation);
    const wallThick = 0.15;
    const roomWidth = 7.30;
    const roomDepth = 3.53;
    const bathDepth = 1.25;
    const balconyDepth = 1.0;

    // Safety padding for visual items (railings, etc.)
    const padding = 0.05;

    // Y-ranges for zones
    const dormZStart = roomDepth / 2;
    const dormZEnd = -roomDepth / 2;
    const annexZEnd = dormZEnd - bathDepth;
    const balconyZEnd = annexZEnd - balconyDepth;

    // Opening widths
    const annexOpeningWidth = 1.5;
    const balconyOpeningWidth = 0.8;

    let targetX = pos[0];
    let targetZ = pos[2];

    // Horizontal clamping (global room width)
    const maxX = (roomWidth / 2) - (w / 2) - padding;
    targetX = Math.max(-maxX, Math.min(maxX, targetX));

    // Zone Clamping
    if (targetZ > dormZEnd + (d / 2) + padding) {
      // In Dorm Zone
      targetZ = Math.min(dormZStart - (d / 2) - padding, targetZ);
    } else if (targetZ < balconyZEnd + (d / 2) + padding) {
      // Below Balcony (outside)
      targetZ = balconyZEnd + (d / 2) + padding;
    } else {
      // In Transition or Annex/Balcony
      // Only CHAIR can enter these zones
      if (type !== 'CHAIR') {
        targetZ = dormZEnd + (d / 2) + padding;
      } else {
        // Transition Check: Dorm -> Annex (1.5m centered opening)
        const inAnnexOpening = Math.abs(targetX) < (annexOpeningWidth / 2 - w / 2);

        if (targetZ < dormZEnd && targetZ > annexZEnd) {
          // Inside Annex area
          if (!inAnnexOpening && targetZ > dormZEnd - (d/2)) {
             targetZ = dormZEnd + (d/2) + padding; // Push back to Dorm if not in opening
          } else {
             // In Annex
             // Check transition: Annex -> Balcony (0.8m centered opening)
             const inBalconyOpening = Math.abs(targetX) < (balconyOpeningWidth / 2 - w / 2);
             if (targetZ < annexZEnd + (d/2) + padding && !inBalconyOpening) {
               targetZ = annexZEnd + (d/2) + padding; // Clamp to Balcony wall
             }
          }
        } else if (targetZ <= annexZEnd) {
          // Inside Balcony area
          const inBalconyOpening = Math.abs(targetX) < (balconyOpeningWidth / 2 - w / 2);
          if (!inBalconyOpening && targetZ > annexZEnd - (d/2)) {
             targetZ = annexZEnd + (d/2) + padding; // Push back to Annex if not in opening
          } else {
             // Free movement in balcony
             targetZ = Math.max(balconyZEnd + (d/2) + padding, targetZ);
          }
        }
      }
    }

    return [targetX, 0, targetZ];
  }, [state.room, getEffectiveDims]);

  const addItem = (type: FurnitureType) => {
    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };
    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId) return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId) return;
    setState(prev => {
      const updatedItems = prev.placedItems.map(i => {
        if (i.instanceId === prev.selectedId) {
          const newRotation = i.rotation + Math.PI / 2;
          return { 
            ...i, 
            rotation: newRotation, 
            position: clampPosition(i.position, i.type, newRotation) 
          };
        }
        return i;
      });
      return { ...prev, placedItems: updatedItems };
    });
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;

    const snappedX = Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE;
    const snappedZ = Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE;

    const clampedPos = clampPosition([snappedX, 0, snappedZ], item.type, item.rotation);

    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => i.instanceId === id ? { ...i, position: clampedPos } : i),
    }));
  }, [state.placedItems, clampPosition]);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Layout saved!");
  };

  return (
    <div className="flex h-screen bg-neutral-100 flex-col md:flex-row overflow-hidden font-sans select-none">
      <aside className="w-full md:w-80 bg-white border-r border-neutral-300 flex flex-col z-20 shadow-2xl">
        <div className="p-6 border-b border-neutral-100 flex items-center gap-3 bg-neutral-50">
          <div className="p-2 bg-blue-600 rounded-lg text-white"><Home size={20}/></div>
          <div>
            <h1 className="text-lg font-bold text-neutral-900 tracking-tight leading-none">DormPlanner</h1>
            <p className="text-[10px] text-neutral-500 font-black uppercase mt-1 tracking-widest">v1.3 Pro</p>
          </div>
        </div>

        <div className="p-6 space-y-6 flex-1 overflow-y-auto">
          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3 flex items-center gap-2">
              <Palette size={12}/> Color Options
            </h2>
            <div className="flex gap-2">
              {Object.entries(THEMES).map(([key, t]) => (
                <button
                  key={key}
                  onClick={() => setTheme(t)}
                  className={`flex-1 h-10 rounded-lg border-2 transition-all ${theme === t ? 'border-blue-500 scale-95 shadow-inner' : 'border-neutral-200'}`}
                  style={{ backgroundColor: t.floor }}
                />
              ))}
            </div>
          </section>

          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3">Add Furniture</h2>
            <div className="grid grid-cols-1 gap-2">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                return (
                  <button key={type} onClick={() => addItem(type)}
                    className="group w-full flex items-center justify-between p-3 rounded-xl border-2 border-neutral-100 bg-white hover:border-blue-500 hover:bg-blue-50 transition-all">
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl transition-transform group-hover:scale-110">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-bold text-sm text-neutral-800">{item.name}</div>
                        <div className="text-[10px] text-neutral-500">{Math.round(item.dimensions.width*100)}x{Math.round(item.dimensions.depth*100)}cm</div>
                      </div>
                    </div>
                    <Plus size={14} className="text-neutral-300 group-hover:text-blue-500" />
                  </button>
                );
              })}
            </div>
          </section>

          {state.selectedId && (
            <section className="animate-in slide-in-from-bottom-2 p-4 bg-neutral-900 rounded-2xl shadow-xl text-white">
              <div className="flex items-center justify-between mb-3">
                 <h3 className="text-[10px] font-bold text-neutral-400 uppercase flex items-center gap-2">
                  <MousePointer2 size={12}/> Interaction
                </h3>
                {collisions.has(state.selectedId) && (
                  <div className="flex items-center gap-1 text-red-400 text-[10px] font-bold">
                    <AlertTriangle size={12} /> Overlap Detected
                  </div>
                )}
              </div>
              <div className="flex gap-2">
                <button onClick={rotateItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-blue-600 rounded-xl hover:bg-blue-500 transition-all">
                  <RotateCw size={18} /><span className="text-[10px] font-black mt-1 uppercase">Rotate</span>
                </button>
                <button onClick={removeItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-red-600 rounded-xl hover:bg-red-500 transition-all">
                  <Trash2 size={18} /><span className="text-[10px] font-black mt-1 uppercase">Remove</span>
                </button>
              </div>
            </section>
          )}
        </div>

        <div className="p-6 border-t border-neutral-100">
          <button onClick={saveLayout} className="w-full flex items-center justify-center space-x-2 py-4 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 transition-all shadow-xl">
            <Save size={18} /> <span>Save Plan</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 relative bg-neutral-100">
        <div className="absolute top-6 right-6 z-10 flex flex-col space-y-2">
          <button onClick={() => setState(p => ({ ...p, showGrid: !p.showGrid }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.showGrid ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
            <Grid3X3 size={24}/>
          </button>
          <button onClick={() => setState(p => ({ ...p, is2D: !p.is2D }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.is2D ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
            {state.is2D ? <Maximize size={24}/> : <Layers size={24}/>}
          </button>
        </div>

        <Canvas shadows dpr={[1, 1.5]} gl={{ antialias: true }}>
          <AdaptiveDpr pixelated />
          <AdaptiveEvents />
          <PerspectiveCamera makeDefault position={state.is2D ? [0, 15, 0] : [10, 10, 10]} fov={state.is2D ? 30 : 45} />

          <OrbitControls 
            enabled={!isDraggingAny}
            enableRotate={!state.is2D} 
            maxPolarAngle={Math.PI / 2.1} 
            makeDefault 
            minDistance={4} 
            maxDistance={40} 
            target={[0, 0, 0]}
          />

          <ambientLight intensity={0.9} />
          <directionalLight position={[10, 20, 10]} intensity={1.5} castShadow shadow-mapSize={[1024, 1024]} />
          <Environment preset="apartment" />

          <RoomStructure theme={theme} showGrid={state.showGrid} config={state.room} onDeselect={() => setState(p => ({ ...p, selectedId: null }))} />

          {state.placedItems.map((item) => (
            <DraggableFurniture 
              key={item.instanceId} 
              item={item} 
              selected={state.selectedId === item.instanceId} 
              hasCollision={collisions.has(item.instanceId)}
              onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))} 
              onDrag={(pos) => handleDrag(item.instanceId, pos)}
              onDragStart={() => setIsDraggingAny(true)}
              onDragEnd={() => setIsDraggingAny(false)}
            />
          ))}

          <ContactShadows resolution={1024} scale={50} blur={2.5} opacity={0.4} far={20} color="#000000" />
        </Canvas>
      </main>
    </div>
  );
}

