        <Text position={[width/4, 0, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#1e293b" fillOpacity={0.5} fontWeight="bold">TOILET</Text>
        <Text position={[0, 0, -depth/2 - bathDepth - balconyDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#fff" fillOpacity={0.7} fontWeight="bold">BALCONY</Text>
      </group>

      {showGrid && (
        <Grid infiniteGrid fadeDistance={40} fadeStrength={5} sectionSize={1} cellSize={GRID_SIZE} sectionColor={theme.accent} cellColor={theme.grid} position={[0, 0.01, 0]} />
      )}

      {/* WALL SEGMENTS */}
      <group>
        {/* Entrance wall segments (116cm centered opening) */}
        <mesh position={[- (width/2 - 3.07/2), height/2, depth/2]}>
          <boxGeometry args={[3.07, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[ (width/2 - 3.07/2), height/2, depth/2]}>
          <boxGeometry args={[3.07, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* Outer full side walls */}
        <mesh position={[-width/2, height/2, -bathDepth/2]}>
          <boxGeometry args={[wallThickness, height, depth + bathDepth]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[width/2, height/2, -bathDepth/2]}>
          <boxGeometry args={[wallThickness, height, depth + bathDepth]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* Middle partition segments (150cm centered opening) */}
        <mesh position={[- (width/2 - 2.9/2), height/2, -depth/2]}>
          <boxGeometry args={[2.9, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[ (width/2 - 2.9/2), height/2, -depth/2]}>
          <boxGeometry args={[2.9, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* Balcony partition segments (80cm centered opening) */}
        <mesh position={[- (width/2 - 3.25/2), height/2, -depth/2 - bathDepth]}>
          <boxGeometry args={[3.25, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>
        <mesh position={[ (width/2 - 3.25/2), height/2, -depth/2 - bathDepth]}>
          <boxGeometry args={[3.25, height, wallThickness]} />
          <meshStandardMaterial color={theme.wall} />
        </mesh>

        {/* Translucent balcony railing */}
        <mesh position={[0, 0.6, -depth/2 - bathDepth - balconyDepth]}>
          <boxGeometry args={[width, 1.2, 0.05]} />
