import React from 'react';
import { FurnitureType } from '../types';
import { FURNITURE_DATA } from '../constants';

interface ModelProps {
  type: FurnitureType;
  selected?: boolean;
  hasCollision?: boolean;
}

export const FurnitureModel: React.FC<ModelProps> = ({ type, selected, hasCollision }) => {
  const data = FURNITURE_DATA[type];
  const { width, height, depth } = data.dimensions;

  const baseMaterialProps = {
    color: hasCollision ? '#ef4444' : (selected ? '#3B82F6' : data.color),
    roughness: 0.4,
    metalness: 0.6,
  };

  switch (type) {
    case 'BUNKER_BED':
      return (
        <group>
          {/* Main frame posts - pulled strictly inside to avoid wall bleed */}
          {[[-1, -1], [-1, 1], [1, -1], [1, 1]].map(([x, z], i) => (
            <mesh key={i} position={[(x * (width - 0.05)) / 2, 0.9, (z * (depth - 0.05)) / 2]}>
              <boxGeometry args={[0.045, 1.8, 0.045]} />
              <meshStandardMaterial {...baseMaterialProps} />
            </mesh>
          ))}
          {/* Bunk Frames */}
          <mesh position={[0, 0.4, 0]}><boxGeometry args={[width - 0.05, 0.05, depth - 0.05]} /><meshStandardMaterial {...baseMaterialProps} /></mesh>
          <mesh position={[0, 1.4, 0]}><boxGeometry args={[width - 0.05, 0.05, depth - 0.05]} /><meshStandardMaterial {...baseMaterialProps} /></mesh>
          {/* Mattresses */}
          <mesh position={[0, 0.5, 0]}><boxGeometry args={[width - 0.1, 0.12, depth - 0.1]} /><meshStandardMaterial color="#f8fafc" /></mesh>
          <mesh position={[0, 1.5, 0]}><boxGeometry args={[width - 0.1, 0.12, depth - 0.1]} /><meshStandardMaterial color="#f8fafc" /></mesh>
          {/* Railings top bunk - tucked inside */}
          <mesh position={[0, 1.7, depth/2 - 0.025]}><boxGeometry args={[width - 0.05, 0.1, 0.02]} /><meshStandardMaterial {...baseMaterialProps} /></mesh>
          <mesh position={[0, 1.7, -depth/2 + 0.025]}><boxGeometry args={[width - 0.05, 0.1, 0.02]} /><meshStandardMaterial {...baseMaterialProps} /></mesh>
        </group>
      );

    case 'STUDY_TABLE':
      return (
        <group position={[0, 0.75, 0]}>
          {/* Table top */}
          <mesh>
            <boxGeometry args={[width - 0.05, 0.03, depth - 0.05]} />
            <meshStandardMaterial color="#cbd5e1" roughness={0.3} />
          </mesh>
          {/* Wall Brackets - tucked inside the bounding box completely */}
          <mesh position={[0, -0.1, -depth/2 + 0.08]} rotation={[0, 0, 0]}>
            <boxGeometry args={[width * 0.6, 0.02, 0.05]} />
            <meshStandardMaterial color="#475569" metalness={0.8} />
          </mesh>
          <group position={[0, -0.15, -depth/2 + 0.08]}>
             <mesh position={[-width/4, 0, 0]} rotation={[Math.PI/4, 0, 0]}>
                <boxGeometry args={[0.02, 0.2, 0.02]} />
                <meshStandardMaterial color="#64748b" />
             </mesh>
             <mesh position={[width/4, 0, 0]} rotation={[Math.PI/4, 0, 0]}>
                <boxGeometry args={[0.02, 0.2, 0.02]} />
                <meshStandardMaterial color="#64748b" />
             </mesh>
          </group>
        </group>
      );

    case 'BERO':
      return (
        <group>
          <mesh position={[0, 0.95, 0]}>
            <boxGeometry args={[width - 0.05, 1.9, depth - 0.05]} />
            <meshStandardMaterial {...baseMaterialProps} />
          </mesh>
          <mesh position={[0, 0.95, depth / 2 - 0.025]}>
            <boxGeometry args={[0.01, 1.8, 0.01]} />
            <meshStandardMaterial color="#1e293b" />
          </mesh>
          <mesh position={[-0.05, 1, depth / 2 - 0.025]}>
            <boxGeometry args={[0.02, 0.15, 0.02]} />
            <meshStandardMaterial color="#94a3b8" metalness={1} />
          </mesh>
          <mesh position={[0.05, 1, depth / 2 - 0.025]}>
            <boxGeometry args={[0.02, 0.15, 0.02]} />
            <meshStandardMaterial color="#94a3b8" metalness={1} />
          </mesh>
        </group>
      );

    case 'CHAIR':
      return (
        <group>
          <mesh position={[0, 0.45, 0]}>
            <boxGeometry args={[width - 0.05, 0.05, depth - 0.05]} />
            <meshStandardMaterial {...baseMaterialProps} />
          </mesh>
          <mesh position={[0, 0.75, -depth / 2 + 0.03]}>
            <boxGeometry args={[width - 0.05, 0.6, 0.03]} />
            <meshStandardMaterial {...baseMaterialProps} />
          </mesh>
          {[[-1, -1], [-1, 1], [1, -1], [1, 1]].map(([x, z], i) => (
            <mesh key={i} position={[(x * (width - 0.05)) / 2.3, 0.22, (z * (depth - 0.05)) / 2.3]}>
              <boxGeometry args={[0.03, 0.44, 0.03]} />
              <meshStandardMaterial color="#0f172a" />
            </mesh>
          ))}
        </group>
      );

    default:
      return null;
  }
};

export type FurnitureType = 'BUNKER_BED' | 'STUDY_TABLE' | 'BERO' | 'CHAIR';
export type AppMode = 'edit' | 'view' | 'pov';

export interface Dimensions {
  width: number;
  height: number;
  depth: number;
}

export interface FurnitureDefinition {
  id: FurnitureType;
  name: string;
  icon: string;
  dimensions: Dimensions;
  color: string;
  maxQuantity: number;
}

export interface PlacedItem {
  instanceId: string;
  type: FurnitureType;
  position: [number, number, number];
  rotation: number; // Y-axis rotation in radians
}

export interface RoomConfig {
  width: number;
  depth: number;
  height: number;
}

export interface AppState {
  room: RoomConfig;
  placedItems: PlacedItem[];
  selectedId: string | null;
  showGrid: boolean;
  is2D: boolean;
  mode: AppMode;
}

import React, { useState, useEffect, useCallback, useMemo, memo, useRef } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, ContactShadows, Environment, AdaptiveDpr, AdaptiveEvents, Text, PointerLockControls } from '@react-three/drei';
import * as THREE from 'three';
import { INITIAL_ROOM, FURNITURE_DATA, GRID_SIZE, THEMES } from './constants';
import { FurnitureType, PlacedItem, AppState, RoomConfig, AppMode } from './types';
import { FurnitureModel } from './components/FurnitureModels';
import { Plus, Trash2, Save, Grid3X3, Layers, Maximize, RotateCw, Palette, Home, MousePointer2, AlertTriangle, Eye, Footprints, Settings2 } from 'lucide-react';

const LOCAL_STORAGE_KEY = 'hostel_planner_v12_pov';
const generateId = () => Math.random().toString(36).substr(2, 9);

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  hasCollision: boolean;
  mode: AppMode;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
  onDragStart: () => void;
  onDragEnd: () => void;
}

const DraggableFurniture = memo(({ item, selected, hasCollision, mode, onSelect, onDrag, onDragStart, onDragEnd }: DraggableProps) => {
  const [isDragging, setIsDragging] = useState(false);
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    if (mode !== 'edit') return;
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
    onDragStart();
    e.target.setPointerCapture(e.pointerId);
  };

  const handlePointerUp = (e: any) => {
    if (mode !== 'edit') return;
    setIsDragging(false);
    onDragEnd();
    e.target.releasePointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging || mode !== 'edit') return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  const data = FURNITURE_DATA[item.type];

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
    >
      <FurnitureModel type={item.type} selected={selected && mode === 'edit'} hasCollision={hasCollision && mode === 'edit'} />
      {selected && mode === 'edit' && (
        <group position={[0, 0.01, 0]}>
           <mesh rotation={[-Math.PI/2, 0, 0]}>
              <planeGeometry args={[data.dimensions.width + 0.05, data.dimensions.depth + 0.05]} />
              <meshBasicMaterial color={hasCollision ? "#ef4444" : "#3B82F6"} transparent opacity={0.3} />
           </mesh>
        </group>
      )}
      <mesh visible={false}>
        <boxGeometry args={[data.dimensions.width, 2, data.dimensions.depth]} />
      </mesh>
    </group>
  );
});

const POVControls = () => {
  const { camera } = useThree();
  const moveState = useRef({ forward: false, backward: false, left: false, right: false });
  const velocity = useRef(new THREE.Vector3());
  const direction = useRef(new THREE.Vector3());

  useEffect(() => {
    const onKeyDown = (e: KeyboardEvent) => {
      switch (e.code) {
        case 'KeyW': moveState.current.forward = true; break;
        case 'KeyS': moveState.current.backward = true; break;
        case 'KeyA': moveState.current.left = true; break;
        case 'KeyD': moveState.current.right = true; break;
      }
    };
    const onKeyUp = (e: KeyboardEvent) => {
      switch (e.code) {
        case 'KeyW': moveState.current.forward = false; break;
        case 'KeyS': moveState.current.backward = false; break;
        case 'KeyA': moveState.current.left = false; break;
        case 'KeyD': moveState.current.right = false; break;
      }
    };
    window.addEventListener('keydown', onKeyDown);
    window.addEventListener('keyup', onKeyUp);
    return () => {
      window.removeEventListener('keydown', onKeyDown);
      window.removeEventListener('keyup', onKeyUp);
    };
  }, []);

  useFrame((state, delta) => {
    const speed = 5.0;
    velocity.current.x -= velocity.current.x * 10.0 * delta;
    velocity.current.z -= velocity.current.z * 10.0 * delta;

    direction.current.z = Number(moveState.current.forward) - Number(moveState.current.backward);
    direction.current.x = Number(moveState.current.right) - Number(moveState.current.left);
    direction.current.normalize();

    if (moveState.current.forward || moveState.current.backward) velocity.current.z -= direction.current.z * speed * 20.0 * delta;
    if (moveState.current.left || moveState.current.right) velocity.current.x -= direction.current.x * speed * 20.0 * delta;

    camera.translateX(-velocity.current.x * delta);
    camera.translateZ(velocity.current.z * delta);
    camera.position.y = 1.6; // Keep eye level
  });

  return <PointerLockControls />;
};

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
    mode: 'edit',
  });

  const [theme, setTheme] = useState(THEMES.HOSTEL_STANDARD);
  const [isDraggingAny, setIsDraggingAny] = useState(false);
  const [collisions, setCollisions] = useState<Set<string>>(new Set());

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed, mode: 'edit' })); // Default back to edit on load
      } catch (e) { console.error("Load failed", e); }
    }
  }, []);

  const getEffectiveDims = useCallback((type: FurnitureType, rotation: number) => {
    const dims = FURNITURE_DATA[type].dimensions;
    const isRotated = Math.round(Math.abs(Math.sin(rotation))) === 1;
    return {
      w: isRotated ? dims.depth : dims.width,
      d: isRotated ? dims.width : dims.depth
    };
  }, []);

  const checkCollisions = useCallback((items: PlacedItem[]) => {
    const collidingIds = new Set<string>();
    for (let i = 0; i < items.length; i++) {
      for (let j = i + 1; j < items.length; j++) {
        const a = items[i];
        const b = items[j];
        const dimA = getEffectiveDims(a.type, a.rotation);
        const dimB = getEffectiveDims(b.type, b.rotation);
        const padding = 0.005;
        const overlapX = Math.abs(a.position[0] - b.position[0]) < (dimA.w + dimB.w) / 2 - padding;
        const overlapZ = Math.abs(a.position[2] - b.position[2]) < (dimA.d + dimB.d) / 2 - padding;
        if (overlapX && overlapZ) {
          collidingIds.add(a.instanceId);
          collidingIds.add(b.instanceId);
        }
      }
    }
    setCollisions(collidingIds);
  }, [getEffectiveDims]);

  useEffect(() => {
    checkCollisions(state.placedItems);
  }, [state.placedItems, checkCollisions]);

  const clampPosition = useCallback((pos: [number, number, number], type: FurnitureType, rotation: number): [number, number, number] => {
    const { w, d } = getEffectiveDims(type, rotation);
    const roomWidth = 7.30;
    const roomDepth = 3.53;
    const bathDepth = 1.25;
    const balconyDepth = 1.0;
    const padding = 0.05;
    const dormZStart = roomDepth / 2;
    const dormZEnd = -roomDepth / 2;
    const annexZEnd = dormZEnd - bathDepth;
    const balconyZEnd = annexZEnd - balconyDepth;
    const annexOpeningWidth = 1.5;
    const balconyOpeningWidth = 0.8;

    let targetX = pos[0];
    let targetZ = pos[2];
    const maxX = (roomWidth / 2) - (w / 2) - padding;
    targetX = Math.max(-maxX, Math.min(maxX, targetX));

    if (targetZ > dormZEnd + (d / 2) + padding) {
      targetZ = Math.min(dormZStart - (d / 2) - padding, targetZ);
    } else if (targetZ < balconyZEnd + (d / 2) + padding) {
      targetZ = balconyZEnd + (d / 2) + padding;
    } else {
      if (type !== 'CHAIR') {
        targetZ = dormZEnd + (d / 2) + padding;
      } else {
        const inAnnexOpening = Math.abs(targetX) < (annexOpeningWidth / 2 - w / 2);
        if (targetZ < dormZEnd && targetZ > annexZEnd) {
          if (!inAnnexOpening && targetZ > dormZEnd - (d/2)) targetZ = dormZEnd + (d/2) + padding;
          else {
             const inBalconyOpening = Math.abs(targetX) < (balconyOpeningWidth / 2 - w / 2);
             if (targetZ < annexZEnd + (d/2) + padding && !inBalconyOpening) targetZ = annexZEnd + (d/2) + padding;
          }
        } else if (targetZ <= annexZEnd) {
          const inBalconyOpening = Math.abs(targetX) < (balconyOpeningWidth / 2 - w / 2);
          if (!inBalconyOpening && targetZ > annexZEnd - (d/2)) targetZ = annexZEnd + (d/2) + padding;
          else targetZ = Math.max(balconyZEnd + (d/2) + padding, targetZ);
        }
      }
    }
    return [targetX, 0, targetZ];
  }, [state.room, getEffectiveDims]);

  const addItem = (type: FurnitureType) => {
    if (state.mode !== 'edit') return;
    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };
    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId || state.mode !== 'edit') return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId || state.mode !== 'edit') return;
    setState(prev => {
      const updatedItems = prev.placedItems.map(i => {
        if (i.instanceId === prev.selectedId) {
          const newRotation = i.rotation + Math.PI / 2;
          return { ...i, rotation: newRotation, position: clampPosition(i.position, i.type, newRotation) };
        }
        return i;
      });
      return { ...prev, placedItems: updatedItems };
    });
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    if (state.mode !== 'edit') return;
    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;
    const snappedX = Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE;
    const snappedZ = Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE;
    const clampedPos = clampPosition([snappedX, 0, snappedZ], item.type, item.rotation);
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => i.instanceId === id ? { ...i, position: clampedPos } : i),
    }));
  }, [state.placedItems, clampPosition, state.mode]);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Layout saved!");
  };

  return (
    <div className="flex h-screen bg-neutral-100 flex-col md:flex-row overflow-hidden font-sans select-none">
      {/* SIDEBAR - Only visible in EDIT mode */}
      <aside className={`w-full md:w-80 bg-white border-r border-neutral-300 flex flex-col z-20 shadow-2xl transition-transform duration-300 ${state.mode !== 'edit' ? '-translate-x-full md:absolute' : 'translate-x-0'}`}>
        <div className="p-6 border-b border-neutral-100 flex items-center gap-3 bg-neutral-50">
          <div className="p-2 bg-blue-600 rounded-lg text-white"><Home size={20}/></div>
          <div>
            <h1 className="text-lg font-bold text-neutral-900 tracking-tight leading-none">DormPlanner</h1>
            <p className="text-[10px] text-neutral-500 font-black uppercase mt-1 tracking-widest tracking-tighter">Interactive Editor</p>
          </div>
        </div>

        <div className="p-6 space-y-6 flex-1 overflow-y-auto">
          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3 flex items-center gap-2">
              <Palette size={12}/> Color Options
            </h2>
            <div className="flex gap-2">
              {Object.entries(THEMES).map(([key, t]) => (
                <button key={key} onClick={() => setTheme(t)} className={`flex-1 h-10 rounded-lg border-2 transition-all ${theme === t ? 'border-blue-500 scale-95 shadow-inner' : 'border-neutral-200'}`} style={{ backgroundColor: t.floor }} />
              ))}
            </div>
          </section>

          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3">Add Furniture</h2>
            <div className="grid grid-cols-1 gap-2">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                return (
                  <button key={type} onClick={() => addItem(type)} className="group w-full flex items-center justify-between p-3 rounded-xl border-2 border-neutral-100 bg-white hover:border-blue-500 hover:bg-blue-50 transition-all">
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl transition-transform group-hover:scale-110">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-bold text-sm text-neutral-800">{item.name}</div>
                        <div className="text-[10px] text-neutral-500">{Math.round(item.dimensions.width*100)}x{Math.round(item.dimensions.depth*100)}cm</div>
                      </div>
                    </div>
                    <Plus size={14} className="text-neutral-300 group-hover:text-blue-500" />
                  </button>
                );
              })}
            </div>
          </section>

          {state.selectedId && (
            <section className="animate-in slide-in-from-bottom-2 p-4 bg-neutral-900 rounded-2xl shadow-xl text-white">
              <div className="flex items-center justify-between mb-3">
                 <h3 className="text-[10px] font-bold text-neutral-400 uppercase flex items-center gap-2">
                  <MousePointer2 size={12}/> Interaction
                </h3>
                {collisions.has(state.selectedId) && (
                  <div className="flex items-center gap-1 text-red-400 text-[10px] font-bold">
                    <AlertTriangle size={12} /> Overlap Detected
                  </div>
                )}
              </div>
              <div className="flex gap-2">
                <button onClick={rotateItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-blue-600 rounded-xl hover:bg-blue-500 transition-all">
                  <RotateCw size={18} /><span className="text-[10px] font-black mt-1 uppercase">Rotate</span>
                </button>
                <button onClick={removeItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-red-600 rounded-xl hover:bg-red-500 transition-all">
                  <Trash2 size={18} /><span className="text-[10px] font-black mt-1 uppercase">Remove</span>
                </button>
              </div>
            </section>
          )}
        </div>

        <div className="p-6 border-t border-neutral-100">
          <button onClick={saveLayout} className="w-full flex items-center justify-center space-x-2 py-4 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 transition-all shadow-xl">
            <Save size={18} /> <span>Save Layout</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 relative bg-neutral-100">
        {/* MODE TOGGLES */}
        <div className="absolute top-6 left-1/2 -translate-x-1/2 z-10 flex bg-white/80 backdrop-blur rounded-2xl p-1 shadow-2xl border border-white/20">
          <button onClick={() => setState(p => ({ ...p, mode: 'edit' }))} className={`px-4 py-2 rounded-xl flex items-center gap-2 text-xs font-bold transition-all ${state.mode === 'edit' ? 'bg-blue-600 text-white' : 'hover:bg-neutral-200 text-neutral-600'}`}>
            <Settings2 size={14} /> EDIT
          </button>
          <button onClick={() => setState(p => ({ ...p, mode: 'view' }))} className={`px-4 py-2 rounded-xl flex items-center gap-2 text-xs font-bold transition-all ${state.mode === 'view' ? 'bg-blue-600 text-white' : 'hover:bg-neutral-200 text-neutral-600'}`}>
            <Eye size={14} /> VIEW
          </button>
          <button onClick={() => setState(p => ({ ...p, mode: 'pov' }))} className={`px-4 py-2 rounded-xl flex items-center gap-2 text-xs font-bold transition-all ${state.mode === 'pov' ? 'bg-blue-600 text-white' : 'hover:bg-neutral-200 text-neutral-600'}`}>
            <Footprints size={14} /> POV
          </button>
        </div>

        {/* CONTROLS OVERLAY */}
        <div className="absolute top-6 right-6 z-10 flex flex-col space-y-2">
          {state.mode === 'edit' && (
            <button onClick={() => setState(p => ({ ...p, showGrid: !p.showGrid }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.showGrid ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
              <Grid3X3 size={24}/>
            </button>
          )}
          <button onClick={() => setState(p => ({ ...p, is2D: !p.is2D }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.is2D ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
            {state.is2D ? <Maximize size={24}/> : <Layers size={24}/>}
          </button>
        </div>

        {state.mode === 'pov' && (
          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 z-10 bg-black/60 text-white px-8 py-4 rounded-3xl backdrop-blur-xl border border-white/10 shadow-2xl text-center pointer-events-none">
            <p className="text-lg font-black tracking-widest uppercase mb-1">Walk Mode</p>
            <p className="text-xs text-neutral-300">Click anywhere to start • WASD to Move • ESC to Exit</p>
          </div>
        )}

        {state.mode === 'view' && (
           <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-10 bg-neutral-900/90 text-white px-6 py-2 rounded-full text-[11px] font-bold tracking-widest pointer-events-none shadow-2xl border border-white/10 uppercase">
            Viewing Layout Mode
          </div>
        )}

        <Canvas shadows dpr={[1, 1.5]} gl={{ antialias: true }}>
          <AdaptiveDpr pixelated />
          <AdaptiveEvents />

          {state.mode === 'pov' ? (
             <>
               <PerspectiveCamera makeDefault position={[0, 1.6, 2.5]} fov={75} />
               <POVControls />
             </>
          ) : (
            <>
              <PerspectiveCamera makeDefault position={state.is2D ? [0, 15, 0] : [10, 10, 10]} fov={state.is2D ? 30 : 45} />
              <OrbitControls enabled={!isDraggingAny} enableRotate={!state.is2D} maxPolarAngle={Math.PI / 2.1} makeDefault minDistance={4} maxDistance={40} target={[0, 0, 0]} />
            </>
          )}

          <ambientLight intensity={0.9} />
          <directionalLight position={[10, 20, 10]} intensity={1.5} castShadow shadow-mapSize={[1024, 1024]} />
          <Environment preset="apartment" />

          <RoomStructure theme={theme} showGrid={state.showGrid && state.mode === 'edit'} config={state.room} onDeselect={() => setState(p => ({ ...p, selectedId: null }))} />

          {state.placedItems.map((item) => (
            <DraggableFurniture 
              key={item.instanceId} 
              item={item} 
              selected={state.selectedId === item.instanceId} 
              hasCollision={collisions.has(item.instanceId)}
              mode={state.mode}
              onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))} 
              onDrag={(pos) => handleDrag(item.instanceId, pos)}
              onDragStart={() => setIsDraggingAny(true)}
              onDragEnd={() => setIsDraggingAny(false)}
            />
          ))}

          <ContactShadows resolution={1024} scale={50} blur={2.5} opacity={0.4} far={20} color="#000000" />
        </Canvas>
      </main>
    </div>
  );
}

const RoomStructure = memo(({ config, showGrid, onDeselect, theme }: { config: RoomConfig, showGrid: boolean, onDeselect: () => void, theme: any }) => {
  const { width, depth, height } = config;
  const bathDepth = 1.25;
  const balconyDepth = 1.0;
  const wallThickness = 0.15;

  return (
    <group onPointerMissed={onDeselect}>
      <mesh position={[0, -0.01, 0]} rotation={[-Math.PI/2, 0, 0]} receiveShadow>
        <planeGeometry args={[width, depth]} />
        <meshStandardMaterial color={theme.floor} roughness={0.7} />
      </mesh>
      <mesh position={[0, -0.01, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]}>
        <planeGeometry args={[width, bathDepth]} />
        <meshStandardMaterial color="#cbd5e1" roughness={0.8} />
      </mesh>
      <mesh position={[0, -0.01, -depth/2 - bathDepth - balconyDepth/2]} rotation={[-Math.PI/2, 0, 0]}>
        <planeGeometry args={[width, balconyDepth]} />
        <meshStandardMaterial color="#475569" roughness={1} />
      </mesh>
      <group position={[0, 0.05, 0]}>
        <Text position={[-width/4, 0, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#1e293b" fillOpacity={0.5} fontWeight="bold">BATHROOM</Text>
        <Text position={[width/4, 0, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#1e293b" fillOpacity={0.5} fontWeight="bold">TOILET</Text>
        <Text position={[0, 0, -depth/2 - bathDepth - balconyDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#fff" fillOpacity={0.7} fontWeight="bold">BALCONY</Text>
      </group>
      {showGrid && (
        <Grid infiniteGrid fadeDistance={40} fadeStrength={5} sectionSize={1} cellSize={GRID_SIZE} sectionColor={theme.accent} cellColor={theme.grid} position={[0, 0.01, 0]} />
      )}
      <group>
        <mesh position={[- (width/2 - 3.07/2), height/2, depth/2]}><boxGeometry args={[3.07, height, wallThickness]} /><meshStandardMaterial color={theme.wall} /></mesh>
        <mesh position={[ (width/2 - 3.07/2), height/2, depth/2]}><boxGeometry args={[3.07, height, wallThickness]} /><meshStandardMaterial color={theme.wall} /></mesh>
        <mesh position={[-width/2, height/2, -bathDepth/2]}><boxGeometry args={[wallThickness, height, depth + bathDepth]} /><meshStandardMaterial color={theme.wall} /></mesh>
        <mesh position={[width/2, height/2, -bathDepth/2]}><boxGeometry args={[wallThickness, height, depth + bathDepth]} /><meshStandardMaterial color={theme.wall} /></mesh>
        <mesh position={[- (width/2 - 2.9/2), height/2, -depth/2]}><boxGeometry args={[2.9, height, wallThickness]} /><meshStandardMaterial color={theme.wall} /></mesh>
        <mesh position={[ (width/2 - 2.9/2), height/2, -depth/2]}><boxGeometry args={[2.9, height, wallThickness]} /><meshStandardMaterial color={theme.wall} /></mesh>
        <mesh position={[- (width/2 - 3.25/2), height/2, -depth/2 - bathDepth]}><boxGeometry args={[3.25, height, wallThickness]} /><meshStandardMaterial color={theme.wall} /></mesh>
        <mesh position={[ (width/2 - 3.25/2), height/2, -depth/2 - bathDepth]}><boxGeometry args={[3.25, height, wallThickness]} /><meshStandardMaterial color={theme.wall} /></mesh>
        <mesh position={[0, 0.6, -depth/2 - bathDepth - balconyDepth]}><boxGeometry args={[width, 1.2, 0.05]} /><meshStandardMaterial color="#475569" transparent opacity={0.6} /></mesh>
      </group>
    </group>
  );
});

import React, { useState, useEffect, useCallback, useMemo, memo, useRef } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, ContactShadows, Environment, AdaptiveDpr, AdaptiveEvents, Text, PointerLockControls } from '@react-three/drei';
import * as THREE from 'three';
import { INITIAL_ROOM, FURNITURE_DATA, GRID_SIZE, THEMES } from './constants';
import { FurnitureType, PlacedItem, AppState, RoomConfig, AppMode } from './types';
import { FurnitureModel } from './components/FurnitureModels';
import { Plus, Trash2, Save, Grid3X3, Layers, Maximize, RotateCw, Palette, Home, MousePointer2, AlertTriangle, Eye, Footprints, Settings2, Move } from 'lucide-react';

const LOCAL_STORAGE_KEY = 'hostel_planner_v13_realistic';
const generateId = () => Math.random().toString(36).substr(2, 9);

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  hasCollision: boolean;
  mode: AppMode;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
  onDragStart: () => void;
  onDragEnd: () => void;
}

const DraggableFurniture = memo(({ item, selected, hasCollision, mode, onSelect, onDrag, onDragStart, onDragEnd }: DraggableProps) => {
  const [isDragging, setIsDragging] = useState(false);
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    if (mode !== 'edit') return;
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
    onDragStart();
    e.target.setPointerCapture(e.pointerId);
  };

  const handlePointerUp = (e: any) => {
    if (mode !== 'edit') return;
    setIsDragging(false);
    onDragEnd();
    e.target.releasePointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging || mode !== 'edit') return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
    >
      <FurnitureModel type={item.type} selected={selected && mode === 'edit'} hasCollision={hasCollision && mode === 'edit'} isRealistic={mode === 'pov' || mode === 'view'} />
      {selected && mode === 'edit' && (
        <group position={[0, 0.01, 0]}>
           <mesh rotation={[-Math.PI/2, 0, 0]}>
              <planeGeometry args={[FURNITURE_DATA[item.type].dimensions.width + 0.05, FURNITURE_DATA[item.type].dimensions.depth + 0.05]} />
              <meshBasicMaterial color={hasCollision ? "#ef4444" : "#3B82F6"} transparent opacity={0.3} />
           </mesh>
        </group>
      )}
    </group>
  );
});

const POVControls = ({ joystickVector }: { joystickVector: { x: number, y: number } }) => {
  const { camera } = useThree();
  const moveState = useRef({ forward: false, backward: false, left: false, right: false });
  const velocity = useRef(new THREE.Vector3());
  const direction = useRef(new THREE.Vector3());
  const headBob = useRef(0);

  useEffect(() => {
    const onKeyDown = (e: KeyboardEvent) => {
      switch (e.code) {
        case 'KeyW': moveState.current.forward = true; break;
        case 'KeyS': moveState.current.backward = true; break;
        case 'KeyA': moveState.current.left = true; break;
        case 'KeyD': moveState.current.right = true; break;
      }
    };
    const onKeyUp = (e: KeyboardEvent) => {
      switch (e.code) {
        case 'KeyW': moveState.current.forward = false; break;
        case 'KeyS': moveState.current.backward = false; break;
        case 'KeyA': moveState.current.left = false; break;
        case 'KeyD': moveState.current.right = false; break;
      }
    };
    window.addEventListener('keydown', onKeyDown);
    window.addEventListener('keyup', onKeyUp);
    return () => {
      window.removeEventListener('keydown', onKeyDown);
      window.removeEventListener('keyup', onKeyUp);
    };
  }, []);

  useFrame((state, delta) => {
    // Slower speed for realism
    const speed = 1.8; 
    const friction = 12.0;

    velocity.current.x -= velocity.current.x * friction * delta;
    velocity.current.z -= velocity.current.z * friction * delta;

    // Combine keyboard and joystick
    const kForward = Number(moveState.current.forward) - Number(moveState.current.backward);
    const kRight = Number(moveState.current.right) - Number(moveState.current.left);

    direction.current.z = kForward || -joystickVector.y;
    direction.current.x = kRight || joystickVector.x;
    direction.current.normalize();

    const isMoving = moveState.current.forward || moveState.current.backward || moveState.current.left || moveState.current.right || Math.abs(joystickVector.x) > 0.1 || Math.abs(joystickVector.y) > 0.1;

    if (isMoving) {
      velocity.current.z -= direction.current.z * speed * 30.0 * delta;
      velocity.current.x -= direction.current.x * speed * 30.0 * delta;

      // Head bobbing effect
      headBob.current += delta * 8;
      camera.position.y = 1.6 + Math.sin(headBob.current) * 0.02;
    } else {
      camera.position.y = THREE.MathUtils.lerp(camera.position.y, 1.6, 0.1);
    }

    camera.translateX(-velocity.current.x * delta);
    camera.translateZ(velocity.current.z * delta);

    // Bounds check to stay inside room (approximate)
    camera.position.x = Math.max(-3.4, Math.min(3.4, camera.position.x));
    camera.position.z = Math.max(-3.5, Math.min(1.5, camera.position.z));
  });

  return <PointerLockControls />;
};

const Joystick = ({ onMove }: { onMove: (v: { x: number, y: number }) => void }) => {
  const [pos, setPos] = useState({ x: 0, y: 0 });
  const requestRef = useRef<number>(null);

  const handleTouch = (e: React.TouchEvent | React.MouseEvent) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    let dx = clientX - centerX;
    let dy = clientY - centerY;
    const distance = Math.sqrt(dx*dx + dy*dy);
    const maxRadius = 40;

    if (distance > maxRadius) {
      dx = (dx / distance) * maxRadius;
      dy = (dy / distance) * maxRadius;
    }

    setPos({ x: dx, y: dy });
    onMove({ x: dx / maxRadius, y: dy / maxRadius });
  };

  const reset = () => {
    setPos({ x: 0, y: 0 });
    onMove({ x: 0, y: 0 });
  };

  return (
    <div 
      className="fixed bottom-12 left-12 w-24 h-24 bg-white/20 backdrop-blur-md rounded-full border border-white/30 z-50 flex items-center justify-center touch-none select-none"
      onPointerMove={handleTouch}
      onPointerUp={reset}
      onPointerLeave={reset}
    >
      <div 
        className="w-12 h-12 bg-blue-500 rounded-full shadow-lg flex items-center justify-center pointer-events-none"
        style={{ transform: `translate(${pos.x}px, ${pos.y}px)` }}
      >
        <Move size={20} className="text-white" />
      </div>
    </div>
  );
};

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
    mode: 'edit',
  });

  const [theme, setTheme] = useState(THEMES.HOSTEL_STANDARD);
  const [isDraggingAny, setIsDraggingAny] = useState(false);
  const [collisions, setCollisions] = useState<Set<string>>(new Set());
  const [joystickVector, setJoystickVector] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed, mode: 'edit' }));
      } catch (e) { console.error("Load failed", e); }
    }
  }, []);

  const getEffectiveDims = useCallback((type: FurnitureType, rotation: number) => {
    const dims = FURNITURE_DATA[type].dimensions;
    const isRotated = Math.round(Math.abs(Math.sin(rotation))) === 1;
    return {
      w: isRotated ? dims.depth : dims.width,
      d: isRotated ? dims.width : dims.depth
    };
  }, []);

  const checkCollisions = useCallback((items: PlacedItem[]) => {
    const collidingIds = new Set<string>();
    for (let i = 0; i < items.length; i++) {
      for (let j = i + 1; j < items.length; j++) {
        const a = items[i];
        const b = items[j];
        const dimA = getEffectiveDims(a.type, a.rotation);
        const dimB = getEffectiveDims(b.type, b.rotation);
        const padding = 0.005;
        const overlapX = Math.abs(a.position[0] - b.position[0]) < (dimA.w + dimB.w) / 2 - padding;
        const overlapZ = Math.abs(a.position[2] - b.position[2]) < (dimA.d + dimB.d) / 2 - padding;
        if (overlapX && overlapZ) {
          collidingIds.add(a.instanceId);
          collidingIds.add(b.instanceId);
        }
      }
    }
    setCollisions(collidingIds);
  }, [getEffectiveDims]);

  useEffect(() => {
    checkCollisions(state.placedItems);
  }, [state.placedItems, checkCollisions]);

  const clampPosition = useCallback((pos: [number, number, number], type: FurnitureType, rotation: number): [number, number, number] => {
    const { w, d } = getEffectiveDims(type, rotation);
    const roomWidth = 7.30;
    const roomDepth = 3.53;
    const padding = 0.05;
    const dormZEnd = -roomDepth / 2;
    const annexOpeningWidth = 1.5;
    const balconyOpeningWidth = 0.8;

    let targetX = pos[0];
    let targetZ = pos[2];
    const maxX = (roomWidth / 2) - (w / 2) - padding;
    targetX = Math.max(-maxX, Math.min(maxX, targetX));

    if (targetZ > dormZEnd + (d / 2) + padding) {
      targetZ = Math.min(roomDepth / 2 - (d / 2) - padding, targetZ);
    } else {
      if (type !== 'CHAIR') {
        targetZ = dormZEnd + (d / 2) + padding;
      } else {
        const inAnnexOpening = Math.abs(targetX) < (annexOpeningWidth / 2 - w / 2);
        if (targetZ < dormZEnd && targetZ > -4.78) { // Transition area
          if (!inAnnexOpening && targetZ > dormZEnd - (d/2)) targetZ = dormZEnd + (d/2) + padding;
          else {
             const inBalconyOpening = Math.abs(targetX) < (balconyOpeningWidth / 2 - w / 2);
             if (targetZ < -4.78 + (d/2) + padding && !inBalconyOpening) targetZ = -4.78 + (d/2) + padding;
          }
        } else {
          targetZ = Math.max(-5.78 + (d/2) + padding, targetZ);
        }
      }
    }
    return [targetX, 0, targetZ];
  }, [getEffectiveDims]);

  const addItem = (type: FurnitureType) => {
    if (state.mode !== 'edit') return;
    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };
    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId || state.mode !== 'edit') return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId || state.mode !== 'edit') return;
    setState(prev => {
      const updatedItems = prev.placedItems.map(i => {
        if (i.instanceId === prev.selectedId) {
          const newRotation = i.rotation + Math.PI / 2;
          return { ...i, rotation: newRotation, position: clampPosition(i.position, i.type, newRotation) };
        }
        return i;
      });
      return { ...prev, placedItems: updatedItems };
    });
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    if (state.mode !== 'edit') return;
    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;
    const snappedX = Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE;
    const snappedZ = Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE;
    const clampedPos = clampPosition([snappedX, 0, snappedZ], item.type, item.rotation);
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => i.instanceId === id ? { ...i, position: clampedPos } : i),
    }));
  }, [state.placedItems, clampPosition, state.mode]);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Layout saved!");
  };

  return (
    <div className="flex h-screen bg-neutral-900 flex-col md:flex-row overflow-hidden font-sans select-none">
      {/* SIDEBAR */}
      <aside className={`w-full md:w-80 bg-white border-r border-neutral-300 flex flex-col z-20 shadow-2xl transition-transform duration-500 ${state.mode !== 'edit' ? '-translate-x-full md:absolute' : 'translate-x-0'}`}>
        <div className="p-6 border-b border-neutral-100 flex items-center gap-3 bg-neutral-50">
          <div className="p-2 bg-blue-600 rounded-lg text-white"><Home size={20}/></div>
          <div>
            <h1 className="text-lg font-bold text-neutral-900 tracking-tight leading-none">DormPlanner</h1>
            <p className="text-[10px] text-neutral-500 font-black uppercase mt-1 tracking-widest tracking-tighter">Pro Suite</p>
          </div>
        </div>

        <div className="p-6 space-y-6 flex-1 overflow-y-auto">
          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3 flex items-center gap-2">
              <Palette size={12}/> Ambience
            </h2>
            <div className="flex gap-2">
              {Object.entries(THEMES).map(([key, t]) => (
                <button key={key} onClick={() => setTheme(t)} className={`flex-1 h-10 rounded-lg border-2 transition-all ${theme === t ? 'border-blue-500 scale-95 shadow-inner' : 'border-neutral-200'}`} style={{ backgroundColor: t.floor }} />
              ))}
            </div>
          </section>

          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3">Add Furniture</h2>
            <div className="grid grid-cols-1 gap-2">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                return (
                  <button key={type} onClick={() => addItem(type)} className="group w-full flex items-center justify-between p-3 rounded-xl border-2 border-neutral-100 bg-white hover:border-blue-500 hover:bg-blue-50 transition-all">
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl transition-transform group-hover:scale-110">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-bold text-sm text-neutral-800">{item.name}</div>
                        <div className="text-[10px] text-neutral-500">{Math.round(item.dimensions.width*100)}x{Math.round(item.dimensions.depth*100)}cm</div>
                      </div>
                    </div>
                    <Plus size={14} className="text-neutral-300 group-hover:text-blue-500" />
                  </button>
                );
              })}
            </div>
          </section>

          {state.selectedId && (
            <section className="animate-in slide-in-from-bottom-2 p-4 bg-neutral-900 rounded-2xl shadow-xl text-white">
              <div className="flex items-center justify-between mb-3">
                 <h3 className="text-[10px] font-bold text-neutral-400 uppercase flex items-center gap-2">
                  <MousePointer2 size={12}/> Edit Selected
                </h3>
              </div>
              <div className="flex gap-2">
                <button onClick={rotateItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-blue-600 rounded-xl hover:bg-blue-500 transition-all">
                  <RotateCw size={18} /><span className="text-[10px] font-black mt-1 uppercase">Rotate</span>
                </button>
                <button onClick={removeItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-red-600 rounded-xl hover:bg-red-500 transition-all">
                  <Trash2 size={18} /><span className="text-[10px] font-black mt-1 uppercase">Delete</span>
                </button>
              </div>
            </section>
          )}
        </div>

        <div className="p-6 border-t border-neutral-100">
          <button onClick={saveLayout} className="w-full flex items-center justify-center space-x-2 py-4 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 transition-all shadow-xl">
            <Save size={18} /> <span>Save Workspace</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 relative bg-neutral-900">
        {/* MODE TOGGLES */}
        <div className="absolute top-6 left-1/2 -translate-x-1/2 z-10 flex bg-white/10 backdrop-blur-xl rounded-2xl p-1 shadow-2xl border border-white/20">
          <button onClick={() => setState(p => ({ ...p, mode: 'edit' }))} className={`px-4 py-2 rounded-xl flex items-center gap-2 text-xs font-bold transition-all ${state.mode === 'edit' ? 'bg-blue-600 text-white' : 'hover:bg-white/10 text-white'}`}>
            <Settings2 size={14} /> EDIT
          </button>
          <button onClick={() => setState(p => ({ ...p, mode: 'view' }))} className={`px-4 py-2 rounded-xl flex items-center gap-2 text-xs font-bold transition-all ${state.mode === 'view' ? 'bg-blue-600 text-white' : 'hover:bg-white/10 text-white'}`}>
            <Eye size={14} /> VIEW
          </button>
          <button onClick={() => setState(p => ({ ...p, mode: 'pov' }))} className={`px-4 py-2 rounded-xl flex items-center gap-2 text-xs font-bold transition-all ${state.mode === 'pov' ? 'bg-blue-600 text-white' : 'hover:bg-white/10 text-white'}`}>
            <Footprints size={14} /> POV
          </button>
        </div>

        {/* CONTROLS OVERLAY */}
        <div className="absolute top-6 right-6 z-10 flex flex-col space-y-2">
          {state.mode === 'edit' && (
            <button onClick={() => setState(p => ({ ...p, showGrid: !p.showGrid }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.showGrid ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
              <Grid3X3 size={24}/>
            </button>
          )}
          <button onClick={() => setState(p => ({ ...p, is2D: !p.is2D }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.is2D ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
            {state.is2D ? <Maximize size={24}/> : <Layers size={24}/>}
          </button>
        </div>

        {state.mode === 'pov' && (
          <>
            <Joystick onMove={setJoystickVector} />
            <div className="absolute top-20 left-1/2 -translate-x-1/2 z-10 text-white/40 text-[10px] font-black tracking-widest uppercase text-center pointer-events-none">
              Move slower for realism • High Fidelity Enabled
            </div>
          </>
        )}

        <Canvas shadows dpr={[1, 2]} gl={{ antialias: true, toneMapping: THREE.ReinhardToneMapping }}>
          <AdaptiveDpr pixelated />
          <AdaptiveEvents />

          {state.mode === 'pov' ? (
             <>
               <PerspectiveCamera makeDefault position={[0, 1.6, 2.5]} fov={60} />
               <POVControls joystickVector={joystickVector} />
             </>
          ) : (
            <>
              <PerspectiveCamera makeDefault position={state.is2D ? [0, 15, 0] : [8, 8, 8]} fov={state.is2D ? 25 : 40} />
              <OrbitControls enabled={!isDraggingAny} enableRotate={!state.is2D} maxPolarAngle={Math.PI / 2.1} makeDefault minDistance={2} maxDistance={40} target={[0, 0, 0]} />
            </>
          )}

          <ambientLight intensity={state.mode === 'pov' ? 0.3 : 0.8} />
          <directionalLight position={[10, 20, 10]} intensity={state.mode === 'pov' ? 0.5 : 1.5} castShadow shadow-mapSize={[2048, 2048]} />

          {/* Realistic Room Interior Lighting */}
          {(state.mode === 'pov' || state.mode === 'view') && (
            <>
              <pointLight position={[0, 2.5, 0]} intensity={2} color="#fffcf0" distance={10} decay={2} castShadow />
              <pointLight position={[3, 2.2, -4]} intensity={1.5} color="#fffcf0" distance={5} decay={2} />
              <pointLight position={[-3, 2.2, -4]} intensity={1.5} color="#fffcf0" distance={5} decay={2} />
            </>
          )}

          <Environment preset="apartment" background={state.mode === 'pov'} backgroundBlurriness={0.5} />

          <RoomStructure theme={theme} showGrid={state.showGrid && state.mode === 'edit'} config={state.room} onDeselect={() => setState(p => ({ ...p, selectedId: null }))} mode={state.mode} />

          {state.placedItems.map((item) => (
            <DraggableFurniture 
              key={item.instanceId} 
              item={item} 
              selected={state.selectedId === item.instanceId} 
              hasCollision={collisions.has(item.instanceId)}
              mode={state.mode}
              onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))} 
              onDrag={(pos) => handleDrag(item.instanceId, pos)}
              onDragStart={() => setIsDraggingAny(true)}
              onDragEnd={() => setIsDraggingAny(false)}
            />
          ))}

          <ContactShadows resolution={1024} scale={50} blur={2} opacity={0.6} far={20} color="#000" />
        </Canvas>
      </main>
    </div>
  );
}

const RoomStructure = memo(({ config, showGrid, onDeselect, theme, mode }: { config: RoomConfig, showGrid: boolean, onDeselect: () => void, theme: any, mode: AppMode }) => {
  const { width, depth, height } = config;
  const bathDepth = 1.25;
  const balconyDepth = 1.0;
  const wallThickness = 0.15;

  return (
    <group onPointerMissed={onDeselect}>
      {/* FLOORS */}
      <mesh position={[0, -0.01, 0]} rotation={[-Math.PI/2, 0, 0]} receiveShadow>
        <planeGeometry args={[width, depth]} />
        <meshStandardMaterial color={theme.floor} roughness={0.6} metalness={0.1} />
      </mesh>
      <mesh position={[0, -0.01, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} receiveShadow>
        <planeGeometry args={[width, bathDepth]} />
        <meshStandardMaterial color="#d1d5db" roughness={0.3} metalness={0.2} />
      </mesh>
      <mesh position={[0, -0.01, -depth/2 - bathDepth - balconyDepth/2]} rotation={[-Math.PI/2, 0, 0]} receiveShadow>
        <planeGeometry args={[width, balconyDepth]} />
        <meshStandardMaterial color="#374151" roughness={0.9} />
      </mesh>

      {/* LABELS - Hide in POV for realism */}
      {mode !== 'pov' && (
        <group position={[0, 0.05, 0]}>
          <Text position={[-width/4, 0, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#1e293b" fillOpacity={0.5} fontWeight="bold">BATHROOM</Text>
          <Text position={[width/4, 0, -depth/2 - bathDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#1e293b" fillOpacity={0.5} fontWeight="bold">TOILET</Text>
          <Text position={[0, 0, -depth/2 - bathDepth - balconyDepth/2]} rotation={[-Math.PI/2, 0, 0]} fontSize={0.2} color="#fff" fillOpacity={0.7} fontWeight="bold">BALCONY</Text>
        </group>
      )}

      {showGrid && (
        <Grid infiniteGrid fadeDistance={40} fadeStrength={5} sectionSize={1} cellSize={GRID_SIZE} sectionColor={theme.accent} cellColor={theme.grid} position={[0, 0.01, 0]} />
      )}

      {/* WALLS */}
      <group>
        {/* Main Walls with realistic thickness and slight bevel logic via boxGeometry */}
        <mesh position={[- (width/2 - 3.07/2), height/2, depth/2]} receiveShadow castShadow><boxGeometry args={[3.07, height, wallThickness]} /><meshStandardMaterial color={theme.wall} roughness={0.8} /></mesh>
        <mesh position={[ (width/2 - 3.07/2), height/2, depth/2]} receiveShadow castShadow><boxGeometry args={[3.07, height, wallThickness]} /><meshStandardMaterial color={theme.wall} roughness={0.8} /></mesh>

        <mesh position={[-width/2, height/2, -bathDepth/2]} receiveShadow castShadow><boxGeometry args={[wallThickness, height, depth + bathDepth]} /><meshStandardMaterial color={theme.wall} roughness={0.8} /></mesh>
        <mesh position={[width/2, height/2, -bathDepth/2]} receiveShadow castShadow><boxGeometry args={[wallThickness, height, depth + bathDepth]} /><meshStandardMaterial color={theme.wall} roughness={0.8} /></mesh>

        <mesh position={[- (width/2 - 2.9/2), height/2, -depth/2]} receiveShadow castShadow><boxGeometry args={[2.9, height, wallThickness]} /><meshStandardMaterial color={theme.wall} roughness={0.8} /></mesh>
        <mesh position={[ (width/2 - 2.9/2), height/2, -depth/2]} receiveShadow castShadow><boxGeometry args={[2.9, height, wallThickness]} /><meshStandardMaterial color={theme.wall} roughness={0.8} /></mesh>

        <mesh position={[- (width/2 - 3.25/2), height/2, -depth/2 - bathDepth]} receiveShadow castShadow><boxGeometry args={[3.25, height, wallThickness]} /><meshStandardMaterial color={theme.wall} roughness={0.8} /></mesh>
        <mesh position={[ (width/2 - 3.25/2), height/2, -depth/2 - bathDepth]} receiveShadow castShadow><boxGeometry args={[3.25, height, wallThickness]} /><meshStandardMaterial color={theme.wall} roughness={0.8} /></mesh>

        {/* Translucent balcony glass railing for realism */}
        <mesh position={[0, 0.6, -depth/2 - bathDepth - balconyDepth]}>
          <boxGeometry args={[width, 1.2, 0.04]} />
          <meshPhysicalMaterial color="#94a3b8" transmission={0.9} thickness={0.1} roughness={0.1} transparent opacity={0.4} />
        </mesh>
      </group>
    </group>
  );
});

import React from 'react';
import { FurnitureType } from '../types';
import { FURNITURE_DATA } from '../constants';

interface ModelProps {
  type: FurnitureType;
  selected?: boolean;
  hasCollision?: boolean;
  isRealistic?: boolean;
}

export const FurnitureModel: React.FC<ModelProps> = ({ type, selected, hasCollision, isRealistic }) => {
  const data = FURNITURE_DATA[type];
  const { width, height, depth } = data.dimensions;

  const getMaterial = (color: string, metal: number = 0.6, rough: number = 0.4) => {
    return {
      color: hasCollision ? '#ef4444' : (selected ? '#3B82F6' : color),
      roughness: isRealistic ? rough * 0.8 : rough,
      metalness: isRealistic ? metal : metal * 0.5,
      envMapIntensity: isRealistic ? 1.5 : 1,
    };
  };

  switch (type) {
    case 'BUNKER_BED':
      const frameMat = getMaterial(data.color, 0.8, 0.3);
      const mattressMat = { color: '#ffffff', roughness: 0.9, envMapIntensity: 0.5 };
      return (
        <group>
          {/* Main frame posts */}
          {[[-1, -1], [-1, 1], [1, -1], [1, 1]].map(([x, z], i) => (
            <mesh key={i} position={[(x * (width - 0.05)) / 2, 0.9, (z * (depth - 0.05)) / 2]} castShadow receiveShadow>
              <boxGeometry args={[0.045, 1.8, 0.045]} />
              <meshStandardMaterial {...frameMat} />
            </mesh>
          ))}
          {/* Bunk Frames */}
          <mesh position={[0, 0.4, 0]} castShadow receiveShadow><boxGeometry args={[width - 0.05, 0.05, depth - 0.05]} /><meshStandardMaterial {...frameMat} /></mesh>
          <mesh position={[0, 1.4, 0]} castShadow receiveShadow><boxGeometry args={[width - 0.05, 0.05, depth - 0.05]} /><meshStandardMaterial {...frameMat} /></mesh>
          {/* Mattresses with subtle side detailing */}
          <mesh position={[0, 0.5, 0]} castShadow receiveShadow><boxGeometry args={[width - 0.1, 0.15, depth - 0.1]} /><meshStandardMaterial {...mattressMat} /></mesh>
          <mesh position={[0, 1.5, 0]} castShadow receiveShadow><boxGeometry args={[width - 0.1, 0.15, depth - 0.1]} /><meshStandardMaterial {...mattressMat} /></mesh>
          {/* Railings top bunk */}
          <mesh position={[0, 1.7, depth/2 - 0.025]} castShadow><boxGeometry args={[width - 0.05, 0.12, 0.02]} /><meshStandardMaterial {...frameMat} /></mesh>
          <mesh position={[0, 1.7, -depth/2 + 0.025]} castShadow><boxGeometry args={[width - 0.05, 0.12, 0.02]} /><meshStandardMaterial {...frameMat} /></mesh>
          {/* Ladder */}
          <group position={[width/2 - 0.1, 0.9, 0]}>
             <mesh position={[0, 0, -0.15]}><boxGeometry args={[0.02, 1.8, 0.02]} /><meshStandardMaterial {...frameMat} /></mesh>
             <mesh position={[0, 0, 0.15]}><boxGeometry args={[0.02, 1.8, 0.02]} /><meshStandardMaterial {...frameMat} /></mesh>
             {Array.from({length: 6}).map((_, i) => (
               <mesh key={i} position={[0, -0.7 + i*0.28, 0]} rotation={[Math.PI/2, 0, 0]}>
                 <cylinderGeometry args={[0.01, 0.01, 0.3]} />
                 <meshStandardMaterial {...frameMat} />
               </mesh>
             ))}
          </group>
        </group>
      );

    case 'STUDY_TABLE':
      const woodMat = { color: '#a8a29e', roughness: 0.7, metalness: 0.05, envMapIntensity: 0.8 };
      const metalMat = getMaterial('#475569', 1, 0.2);
      return (
        <group position={[0, 0.75, 0]}>
          <mesh castShadow receiveShadow>
            <boxGeometry args={[width - 0.05, 0.03, depth - 0.05]} />
            <meshStandardMaterial {...woodMat} />
          </mesh>
          <mesh position={[0, -0.1, -depth/2 + 0.08]} rotation={[0, 0, 0]} castShadow>
            <boxGeometry args={[width * 0.6, 0.02, 0.05]} />
            <meshStandardMaterial {...metalMat} />
          </mesh>
          <group position={[0, -0.15, -depth/2 + 0.08]}>
             <mesh position={[-width/4, 0, 0]} rotation={[Math.PI/4, 0, 0]} castShadow>
                <boxGeometry args={[0.02, 0.2, 0.02]} />
                <meshStandardMaterial {...metalMat} />
             </mesh>
             <mesh position={[width/4, 0, 0]} rotation={[Math.PI/4, 0, 0]} castShadow>
                <boxGeometry args={[0.02, 0.2, 0.02]} />
                <meshStandardMaterial {...metalMat} />
             </mesh>
          </group>
        </group>
      );

    case 'BERO':
      const bodyMat = getMaterial(data.color, 0.9, 0.2);
      const handleMat = { color: '#f8fafc', metalness: 1, roughness: 0.1 };
      return (
        <group>
          <mesh position={[0, 0.95, 0]} castShadow receiveShadow>
            <boxGeometry args={[width - 0.05, 1.9, depth - 0.05]} />
            <meshStandardMaterial {...bodyMat} />
          </mesh>
          {/* Door gap */}
          <mesh position={[0, 0.95, depth / 2 - 0.02]} castShadow>
            <boxGeometry args={[0.005, 1.8, 0.01]} />
            <meshStandardMaterial color="#000000" />
          </mesh>
          {/* Handles */}
          <mesh position={[-0.06, 1, depth / 2 - 0.02]} castShadow>
            <boxGeometry args={[0.02, 0.2, 0.03]} />
            <meshStandardMaterial {...handleMat} />
          </mesh>
          <mesh position={[0.06, 1, depth / 2 - 0.02]} castShadow>
            <boxGeometry args={[0.02, 0.2, 0.03]} />
            <meshStandardMaterial {...handleMat} />
          </mesh>
        </group>
      );

    case 'CHAIR':
      const chairMat = getMaterial(data.color, 0.2, 0.6);
      const legMat = { color: '#000000', metalness: 0.8, roughness: 0.2 };
      return (
        <group>
          <mesh position={[0, 0.45, 0]} castShadow receiveShadow>
            <boxGeometry args={[width - 0.05, 0.05, depth - 0.05]} />
            <meshStandardMaterial {...chairMat} />
          </mesh>
          <mesh position={[0, 0.75, -depth / 2 + 0.03]} castShadow receiveShadow>
            <boxGeometry args={[width - 0.05, 0.6, 0.04]} />
            <meshStandardMaterial {...chairMat} />
          </mesh>
          {[[-1, -1], [-1, 1], [1, -1], [1, 1]].map(([x, z], i) => (
            <mesh key={i} position={[(x * (width - 0.05)) / 2.3, 0.22, (z * (depth - 0.05)) / 2.3]} castShadow>
              <boxGeometry args={[0.03, 0.44, 0.03]} />
              <meshStandardMaterial {...legMat} />
            </mesh>
          ))}
        </group>
      );

    default:
      return null;
  }
};

import React, { useState, useEffect, useCallback, useMemo, memo, useRef } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Grid, PerspectiveCamera, ContactShadows, Environment, AdaptiveDpr, AdaptiveEvents, Text, PointerLockControls } from '@react-three/drei';
import * as THREE from 'three';
import { INITIAL_ROOM, FURNITURE_DATA, GRID_SIZE, THEMES } from './constants';
import { FurnitureType, PlacedItem, AppState, RoomConfig, AppMode } from './types';
import { FurnitureModel } from './components/FurnitureModels';
import { Plus, Trash2, Save, Grid3X3, Layers, Maximize, RotateCw, Palette, Home, MousePointer2, AlertTriangle, Eye, Footprints, Settings2, Move } from 'lucide-react';

const LOCAL_STORAGE_KEY = 'hostel_planner_v13_realistic';
const generateId = () => Math.random().toString(36).substr(2, 9);

interface DraggableProps {
  item: PlacedItem;
  selected: boolean;
  hasCollision: boolean;
  mode: AppMode;
  onSelect: () => void;
  onDrag: (pos: [number, number, number]) => void;
  onDragStart: () => void;
  onDragEnd: () => void;
}

const DraggableFurniture = memo(({ item, selected, hasCollision, mode, onSelect, onDrag, onDragStart, onDragEnd }: DraggableProps) => {
  const [isDragging, setIsDragging] = useState(false);
  const floorPlane = useMemo(() => new THREE.Plane(new THREE.Vector3(0, 1, 0), 0), []);

  const handlePointerDown = (e: any) => {
    if (mode !== 'edit') return;
    e.stopPropagation();
    onSelect();
    setIsDragging(true);
    onDragStart();
    e.target.setPointerCapture(e.pointerId);
  };

  const handlePointerUp = (e: any) => {
    if (mode !== 'edit') return;
    setIsDragging(false);
    onDragEnd();
    e.target.releasePointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: any) => {
    if (!isDragging || mode !== 'edit') return;
    e.stopPropagation();
    const point = new THREE.Vector3();
    e.ray.intersectPlane(floorPlane, point);
    onDrag([point.x, 0, point.z]);
  };

  return (
    <group
      position={item.position}
      rotation={[0, item.rotation, 0]}
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerMove={handlePointerMove}
    >
      <FurnitureModel type={item.type} selected={selected && mode === 'edit'} hasCollision={hasCollision && mode === 'edit'} isRealistic={mode === 'pov' || mode === 'view'} />
      {selected && mode === 'edit' && (
        <group position={[0, 0.01, 0]}>
           <mesh rotation={[-Math.PI/2, 0, 0]}>
              <planeGeometry args={[FURNITURE_DATA[item.type].dimensions.width + 0.05, FURNITURE_DATA[item.type].dimensions.depth + 0.05]} />
              <meshBasicMaterial color={hasCollision ? "#ef4444" : "#3B82F6"} transparent opacity={0.3} />
           </mesh>
        </group>
      )}
    </group>
  );
});

const POVControls = ({ joystickVector }: { joystickVector: { x: number, y: number } }) => {
  const { camera } = useThree();
  const moveState = useRef({ forward: false, backward: false, left: false, right: false, up: false, down: false });
  const velocity = useRef(new THREE.Vector3());
  const direction = useRef(new THREE.Vector3());
  const headBob = useRef(0);

  useEffect(() => {
    const onKeyDown = (e: KeyboardEvent) => {
      switch (e.code) {
        case 'KeyW': moveState.current.forward = true; break;
        case 'KeyS': moveState.current.backward = true; break;
        case 'KeyA': moveState.current.left = true; break;
        case 'KeyD': moveState.current.right = true; break;
        case 'Space': moveState.current.up = true; break;
        case 'ShiftLeft':
        case 'ShiftRight': moveState.current.down = true; break;
      }
    };
    const onKeyUp = (e: KeyboardEvent) => {
      switch (e.code) {
        case 'KeyW': moveState.current.forward = false; break;
        case 'KeyS': moveState.current.backward = false; break;
        case 'KeyA': moveState.current.left = false; break;
        case 'KeyD': moveState.current.right = false; break;
        case 'Space': moveState.current.up = false; break;
        case 'ShiftLeft':
        case 'ShiftRight': moveState.current.down = false; break;
      }
    };
    window.addEventListener('keydown', onKeyDown);
    window.addEventListener('keyup', onKeyUp);
    return () => {
      window.removeEventListener('keydown', onKeyDown);
      window.removeEventListener('keyup', onKeyUp);
    };
  }, []);

  useFrame((state, delta) => {
    // Slower speed for more precise realistic control
    const speed = 1.2; 
    const verticalSpeed = 1.0;
    const friction = 10.0;

    velocity.current.x -= velocity.current.x * friction * delta;
    velocity.current.y -= velocity.current.y * friction * delta;
    velocity.current.z -= velocity.current.z * friction * delta;

    // Combine keyboard and joystick
    const kForward = Number(moveState.current.forward) - Number(moveState.current.backward);
    const kRight = Number(moveState.current.right) - Number(moveState.current.left);
    const kUp = Number(moveState.current.up) - Number(moveState.current.down);

    direction.current.z = kForward || -joystickVector.y;
    direction.current.x = kRight || joystickVector.x;
    direction.current.y = kUp;
    direction.current.normalize();

    const isMovingHorizontal = moveState.current.forward || moveState.current.backward || moveState.current.left || moveState.current.right || Math.abs(joystickVector.x) > 0.1 || Math.abs(joystickVector.y) > 0.1;
    const isMovingVertical = moveState.current.up || moveState.current.down;

    if (isMovingHorizontal) {
      velocity.current.z -= direction.current.z * speed * 25.0 * delta;
      velocity.current.x -= direction.current.x * speed * 25.0 * delta;

      // Head bobbing effect - only if near the ground
      if (camera.position.y < 1.7) {
        headBob.current += delta * 6;
        const bob = Math.sin(headBob.current) * 0.015;
        camera.position.y += bob;
      }
    }

    if (isMovingVertical) {
      velocity.current.y += direction.current.y * verticalSpeed * 25.0 * delta;
    }

    camera.translateX(-velocity.current.x * delta);
    camera.translateZ(velocity.current.z * delta);
    camera.position.y += velocity.current.y * delta;

    // Bounds check to stay inside room
    camera.position.x = Math.max(-3.5, Math.min(3.5, camera.position.x));
    camera.position.z = Math.max(-3.8, Math.min(1.6, camera.position.z));
    // Height bounds: prevent going through floor (0.1) or ceiling (2.7)
    camera.position.y = Math.max(0.2, Math.min(2.7, camera.position.y));
  });

  return <PointerLockControls />;
};

const Joystick = ({ onMove }: { onMove: (v: { x: number, y: number }) => void }) => {
  const [pos, setPos] = useState({ x: 0, y: 0 });

  const handleTouch = (e: React.TouchEvent | React.MouseEvent) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    let dx = clientX - centerX;
    let dy = clientY - centerY;
    const distance = Math.sqrt(dx*dx + dy*dy);
    const maxRadius = 40;

    if (distance > maxRadius) {
      dx = (dx / distance) * maxRadius;
      dy = (dy / distance) * maxRadius;
    }

    setPos({ x: dx, y: dy });
    onMove({ x: dx / maxRadius, y: dy / maxRadius });
  };

  const reset = () => {
    setPos({ x: 0, y: 0 });
    onMove({ x: 0, y: 0 });
  };

  return (
    <div 
      className="fixed bottom-12 left-12 w-24 h-24 bg-white/10 backdrop-blur-md rounded-full border border-white/20 z-50 flex items-center justify-center touch-none select-none shadow-2xl"
      onPointerMove={handleTouch}
      onPointerUp={reset}
      onPointerLeave={reset}
    >
      <div 
        className="w-12 h-12 bg-blue-500/80 rounded-full shadow-lg flex items-center justify-center pointer-events-none"
        style={{ transform: `translate(${pos.x}px, ${pos.y}px)` }}
      >
        <Move size={20} className="text-white" />
      </div>
    </div>
  );
};

export default function App() {
  const [state, setState] = useState<AppState>({
    room: INITIAL_ROOM,
    placedItems: [],
    selectedId: null,
    showGrid: true,
    is2D: false,
    mode: 'edit',
  });

  const [theme, setTheme] = useState(THEMES.HOSTEL_STANDARD);
  const [isDraggingAny, setIsDraggingAny] = useState(false);
  const [collisions, setCollisions] = useState<Set<string>>(new Set());
  const [joystickVector, setJoystickVector] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed, mode: 'edit' }));
      } catch (e) { console.error("Load failed", e); }
    }
  }, []);

  const getEffectiveDims = useCallback((type: FurnitureType, rotation: number) => {
    const dims = FURNITURE_DATA[type].dimensions;
    const isRotated = Math.round(Math.abs(Math.sin(rotation))) === 1;
    return {
      w: isRotated ? dims.depth : dims.width,
      d: isRotated ? dims.width : dims.depth
    };
  }, []);

  const checkCollisions = useCallback((items: PlacedItem[]) => {
    const collidingIds = new Set<string>();
    for (let i = 0; i < items.length; i++) {
      for (let j = i + 1; j < items.length; j++) {
        const a = items[i];
        const b = items[j];
        const dimA = getEffectiveDims(a.type, a.rotation);
        const dimB = getEffectiveDims(b.type, b.rotation);
        const padding = 0.005;
        const overlapX = Math.abs(a.position[0] - b.position[0]) < (dimA.w + dimB.w) / 2 - padding;
        const overlapZ = Math.abs(a.position[2] - b.position[2]) < (dimA.d + dimB.d) / 2 - padding;
        if (overlapX && overlapZ) {
          collidingIds.add(a.instanceId);
          collidingIds.add(b.instanceId);
        }
      }
    }
    setCollisions(collidingIds);
  }, [getEffectiveDims]);

  useEffect(() => {
    checkCollisions(state.placedItems);
  }, [state.placedItems, checkCollisions]);

  const clampPosition = useCallback((pos: [number, number, number], type: FurnitureType, rotation: number): [number, number, number] => {
    const { w, d } = getEffectiveDims(type, rotation);
    const roomWidth = 7.30;
    const roomDepth = 3.53;
    const padding = 0.05;
    const dormZEnd = -roomDepth / 2;
    const annexOpeningWidth = 1.5;
    const balconyOpeningWidth = 0.8;

    let targetX = pos[0];
    let targetZ = pos[2];
    const maxX = (roomWidth / 2) - (w / 2) - padding;
    targetX = Math.max(-maxX, Math.min(maxX, targetX));

    if (targetZ > dormZEnd + (d / 2) + padding) {
      targetZ = Math.min(roomDepth / 2 - (d / 2) - padding, targetZ);
    } else {
      if (type !== 'CHAIR') {
        targetZ = dormZEnd + (d / 2) + padding;
      } else {
        const inAnnexOpening = Math.abs(targetX) < (annexOpeningWidth / 2 - w / 2);
        if (targetZ < dormZEnd && targetZ > -4.78) { // Transition area
          if (!inAnnexOpening && targetZ > dormZEnd - (d/2)) targetZ = dormZEnd + (d/2) + padding;
          else {
             const inBalconyOpening = Math.abs(targetX) < (balconyOpeningWidth / 2 - w / 2);
             if (targetZ < -4.78 + (d/2) + padding && !inBalconyOpening) targetZ = -4.78 + (d/2) + padding;
          }
        } else {
          targetZ = Math.max(-5.78 + (d/2) + padding, targetZ);
        }
      }
    }
    return [targetX, 0, targetZ];
  }, [getEffectiveDims]);

  const addItem = (type: FurnitureType) => {
    if (state.mode !== 'edit') return;
    const newItem: PlacedItem = {
      instanceId: generateId(),
      type,
      position: [0, 0, 0],
      rotation: 0,
    };
    setState(prev => ({
      ...prev,
      placedItems: [...prev.placedItems, newItem],
      selectedId: newItem.instanceId,
    }));
  };

  const removeItem = () => {
    if (!state.selectedId || state.mode !== 'edit') return;
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.filter(i => i.instanceId !== state.selectedId),
      selectedId: null,
    }));
  };

  const rotateItem = () => {
    if (!state.selectedId || state.mode !== 'edit') return;
    setState(prev => {
      const updatedItems = prev.placedItems.map(i => {
        if (i.instanceId === prev.selectedId) {
          const newRotation = i.rotation + Math.PI / 2;
          return { ...i, rotation: newRotation, position: clampPosition(i.position, i.type, newRotation) };
        }
        return i;
      });
      return { ...prev, placedItems: updatedItems };
    });
  };

  const handleDrag = useCallback((id: string, newPos: [number, number, number]) => {
    if (state.mode !== 'edit') return;
    const item = state.placedItems.find(i => i.instanceId === id);
    if (!item) return;
    const snappedX = Math.round(newPos[0] / GRID_SIZE) * GRID_SIZE;
    const snappedZ = Math.round(newPos[2] / GRID_SIZE) * GRID_SIZE;
    const clampedPos = clampPosition([snappedX, 0, snappedZ], item.type, item.rotation);
    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => i.instanceId === id ? { ...i, position: clampedPos } : i),
    }));
  }, [state.placedItems, clampPosition, state.mode]);

  const saveLayout = () => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
      placedItems: state.placedItems,
      room: state.room
    }));
    alert("Layout saved!");
  };

  return (
    <div className="flex h-screen bg-neutral-900 flex-col md:flex-row overflow-hidden font-sans select-none">
      {/* SIDEBAR */}
      <aside className={`w-full md:w-80 bg-white border-r border-neutral-300 flex flex-col z-20 shadow-2xl transition-transform duration-500 ${state.mode !== 'edit' ? '-translate-x-full md:absolute' : 'translate-x-0'}`}>
        <div className="p-6 border-b border-neutral-100 flex items-center gap-3 bg-neutral-50">
          <div className="p-2 bg-blue-600 rounded-lg text-white"><Home size={20}/></div>
          <div>
            <h1 className="text-lg font-bold text-neutral-900 tracking-tight leading-none">DormPlanner</h1>
            <p className="text-[10px] text-neutral-500 font-black uppercase mt-1 tracking-widest tracking-tighter">Pro Suite</p>
          </div>
        </div>

        <div className="p-6 space-y-6 flex-1 overflow-y-auto">
          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3 flex items-center gap-2">
              <Palette size={12}/> Ambience
            </h2>
            <div className="flex gap-2">
              {Object.entries(THEMES).map(([key, t]) => (
                <button key={key} onClick={() => setTheme(t)} className={`flex-1 h-10 rounded-lg border-2 transition-all ${theme === t ? 'border-blue-500 scale-95 shadow-inner' : 'border-neutral-200'}`} style={{ backgroundColor: t.floor }} />
              ))}
            </div>
          </section>

          <section>
            <h2 className="text-[10px] font-black text-neutral-400 uppercase tracking-widest mb-3">Add Furniture</h2>
            <div className="grid grid-cols-1 gap-2">
              {(Object.keys(FURNITURE_DATA) as FurnitureType[]).map(type => {
                const item = FURNITURE_DATA[type];
                return (
                  <button key={type} onClick={() => addItem(type)} className="group w-full flex items-center justify-between p-3 rounded-xl border-2 border-neutral-100 bg-white hover:border-blue-500 hover:bg-blue-50 transition-all">
                    <div className="flex items-center space-x-3">
                      <span className="text-2xl transition-transform group-hover:scale-110">{item.icon}</span>
                      <div className="text-left">
                        <div className="font-bold text-sm text-neutral-800">{item.name}</div>
                        <div className="text-[10px] text-neutral-500">{Math.round(item.dimensions.width*100)}x{Math.round(item.dimensions.depth*100)}cm</div>
                      </div>
                    </div>
                    <Plus size={14} className="text-neutral-300 group-hover:text-blue-500" />
                  </button>
                );
              })}
            </div>
          </section>

          {state.selectedId && (
            <section className="animate-in slide-in-from-bottom-2 p-4 bg-neutral-900 rounded-2xl shadow-xl text-white">
              <div className="flex items-center justify-between mb-3">
                 <h3 className="text-[10px] font-bold text-neutral-400 uppercase flex items-center gap-2">
                  <MousePointer2 size={12}/> Edit Selected
                </h3>
              </div>
              <div className="flex gap-2">
                <button onClick={rotateItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-blue-600 rounded-xl hover:bg-blue-500 transition-all">
                  <RotateCw size={18} /><span className="text-[10px] font-black mt-1 uppercase">Rotate</span>
                </button>
                <button onClick={removeItem} className="flex-1 flex flex-col items-center justify-center p-3 bg-red-600 rounded-xl hover:bg-red-500 transition-all">
                  <Trash2 size={18} /><span className="text-[10px] font-black mt-1 uppercase">Delete</span>
                </button>
              </div>
            </section>
          )}
        </div>

        <div className="p-6 border-t border-neutral-100">
          <button onClick={saveLayout} className="w-full flex items-center justify-center space-x-2 py-4 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 transition-all shadow-xl">
            <Save size={18} /> <span>Save Workspace</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 relative bg-neutral-900">
        {/* MODE TOGGLES */}
        <div className="absolute top-6 left-1/2 -translate-x-1/2 z-10 flex bg-white/10 backdrop-blur-xl rounded-2xl p-1 shadow-2xl border border-white/20">
          <button onClick={() => setState(p => ({ ...p, mode: 'edit' }))} className={`px-4 py-2 rounded-xl flex items-center gap-2 text-xs font-bold transition-all ${state.mode === 'edit' ? 'bg-blue-600 text-white' : 'hover:bg-white/10 text-white'}`}>
            <Settings2 size={14} /> EDIT
          </button>
          <button onClick={() => setState(p => ({ ...p, mode: 'view' }))} className={`px-4 py-2 rounded-xl flex items-center gap-2 text-xs font-bold transition-all ${state.mode === 'view' ? 'bg-blue-600 text-white' : 'hover:bg-white/10 text-white'}`}>
            <Eye size={14} /> VIEW
          </button>
          <button onClick={() => setState(p => ({ ...p, mode: 'pov' }))} className={`px-4 py-2 rounded-xl flex items-center gap-2 text-xs font-bold transition-all ${state.mode === 'pov' ? 'bg-blue-600 text-white' : 'hover:bg-white/10 text-white'}`}>
            <Footprints size={14} /> POV
          </button>
        </div>

        {/* CONTROLS OVERLAY */}
        <div className="absolute top-6 right-6 z-10 flex flex-col space-y-2">
          {state.mode === 'edit' && (
            <button onClick={() => setState(p => ({ ...p, showGrid: !p.showGrid }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.showGrid ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
              <Grid3X3 size={24}/>
            </button>
          )}
          <button onClick={() => setState(p => ({ ...p, is2D: !p.is2D }))} className={`p-4 rounded-2xl shadow-2xl transition-all border-2 ${state.is2D ? 'bg-blue-600 border-blue-400 text-white' : 'bg-white border-neutral-200 text-neutral-400'}`}>
            {state.is2D ? <Maximize size={24}/> : <Layers size={24}/>}
          </button>
        </div>

        {state.mode === 'pov' && (
          <>
            <Joystick onMove={setJoystickVector} />
            <div className="absolute bottom-20 left-1/2 -translate-x-1/2 z-10 bg-black/40 backdrop-blur-md px-6 py-4 rounded-3xl border border-white/10 text-white text-center pointer-events-none">
              <p className="text-xs font-black tracking-widest uppercase mb-1">POV / FLY MODE</p>
              <p className="text-[10px] text-white/70">WASD: Walk • Space: Fly Up • Shift: Fly Down • ESC: Unlock Cursor</p>
            </div>
          </>
        )}

        <Canvas shadows dpr={[1, 2]} gl={{ antialias: true, toneMapping: THREE.ReinhardToneMapping }}>
          <AdaptiveDpr pixelated />
          <AdaptiveEvents />

          {state.mode === 'pov' ? (
             <>
               <PerspectiveCamera makeDefault position={[0, 1.6, 2.5]} fov={60} />
               <POVControls joystickVector={joystickVector} />
             </>
          ) : (
            <>
              <PerspectiveCamera makeDefault position={state.is2D ? [0, 15, 0] : [8, 8, 8]} fov={state.is2D ? 25 : 40} />
              <OrbitControls enabled={!isDraggingAny} enableRotate={!state.is2D} maxPolarAngle={Math.PI / 2.1} makeDefault minDistance={2} maxDistance={40} target={[0, 0, 0]} />
            </>
          )}

          <ambientLight intensity={state.mode === 'pov' ? 0.3 : 0.8} />
          <directionalLight position={[10, 20, 10]} intensity={state.mode === 'pov' ? 0.5 : 1.5} castShadow shadow-mapSize={[2048, 2048]} />

          {/* Realistic Room Interior Lighting */}
          {(state.mode === 'pov' || state.mode === 'view') && (
            <>
              <pointLight position={[0, 2.5, 0]} intensity={2} color="#fffcf0" distance={10} decay={2} castShadow />
              <pointLight position={[3, 2.2, -4]} intensity={1.5} color="#fffcf0" distance={5} decay={2} />
              <pointLight position={[-3, 2.2, -4]} intensity={1.5} color="#fffcf0" distance={5} decay={2} />
            </>
          )}

          <Environment preset="apartment" background={state.mode === 'pov'} backgroundBlurriness={0.5} />

          <RoomStructure theme={theme} showGrid={state.showGrid && state.mode === 'edit'} config={state.room} onDeselect={() => setState(p => ({ ...p, selectedId: null }))} mode={state.mode} />

          {state.placedItems.map((item) => (
            <DraggableFurniture 
              key={item.instanceId} 
              item={item} 
              selected={state.selectedId === item.instanceId} 
              hasCollision={collisions.has(item.instanceId)}
              mode={state.mode}
              onSelect={() => setState(p => ({ ...p, selectedId: item.instanceId }))} 
              onDrag={(pos) => handleDrag(item.instanceId, pos)}
              onDragStart={() => setIsDraggingAny(true)}
              onDragEnd={() => setIsDraggingAny(false)}
            />
          ))}

          <ContactShadows resolution={1024} scale={50} blur={2} opacity={0.6} far={20} color="#000" />
        </Canvas>
      </main>
    </div>
  );
}

