        <div className="p-6 space-y-6 flex-1 overflow-y-auto text-neutral-800">
          <section className="bg-neutral-900 rounded-2xl p-4 shadow-xl border border-white/5 text-white">
             <div className="flex items-center justify-between mb-2">
                <h2 className="text-[10px] font-black text-blue-400 uppercase tracking-widest flex items-center gap-2"><Sparkles size={12}/> Interaction</h2>
