      setChatMessages(prev => [...prev, { role: 'model', text: aiText }]);

      const jsonMatch = rawText.match(/<json>([\s\S]*?)<\/json>/);
      if (jsonMatch) {
        try {
          const items = JSON.parse(jsonMatch[1].trim());
          const placedItems: PlacedItem[] = items.map((item: any) => ({
