    setState(prev => ({
      ...prev,
      placedItems: prev.placedItems.map(i => i.instanceId === id ? { ...i, position: clampPosition([snappedX, 0, snappedZ], i.type, i.rotation) } : i),
    }));
  }, [clampPosition, state.mode]);

