// Helper to extract specific numbers and constraints from user prompt
function parseUserRequest(prompt: string) {
  const p = prompt.toLowerCase();
  const extractNumber = (text: string, term: string) => {
    // Matches "3 beds", "3x beds", "three beds", etc.
    const numberMap: Record<string, number> = { 'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5 };
    const regex = new RegExp(`(\\d+|one|two|three|four|five)\\s*(?:x\\s*)?${term}`, 'i');
    const match = text.match(regex);
    if (!match) return null;
    const val = match[1];
    return isNaN(parseInt(val)) ? numberMap[val] || 1 : parseInt(val);
  };

  return {
    items: {
      beros: extractNumber(p, 'bero') || extractNumber(p, 'wardrobe'),
      chairs: extractNumber(p, 'chair'),
      tables: extractNumber(p, 'table') || extractNumber(p, 'desk'),
      beds: extractNumber(p, 'bed'),
      fans: extractNumber(p, 'fan')
    },
    constraints: {
      wallMounted: p.includes('wall mounted') || p.includes('wall-mounted'),
      closable: p.includes('closable') || p.includes('fold'),
      airCirculation: p.includes('air circulation') || p.includes('airflow') || p.includes('ventilation')
    }
  };
}

